EGG_PROTAGONIST_SURPLUS_ENABLED = _env_bool("MEALFIT_EGG_PROTAGONIST_SURPLUS", True)
SURGICAL_REJECT_RETRY_ENABLED = _env_bool("MEALFIT_SURGICAL_REJECT_RETRY", True)
