# Default OFF: es un gate NUEVO — se enciende con datos de flota (mismo playbook que P1-DISH-QUALITY-GATE-ON:
# la telemetría del banner de arriba mide la tasa real antes del flip). Advisory en intento final al activarse.
# [P1-GATES-FLIP-ON · 2026-07-03] (audit v6 · P1-4) OFF→ON con serie del gym baseline (20 perfiles,
# 2026-07-03): worst-day ceiling en 4/20; el trigger del gate (promedio >techo×1.5) es más raro aún
# y degrada a advisory en intento final → sin riesgo de retry-storm. Baseline tests OFF en conftest.
SODIUM_EXCESS_GATE_ENABLED = _env_bool("MEALFIT_SODIUM_EXCESS_GATE", True)
SODIUM_EXCESS_GATE_RATIO = _env_float("MEALFIT_SODIUM_EXCESS_GATE_RATIO", 1.5)
# [P1-MICRO-PERDAY-FLOOR · 2026-07-02] (audit v4 micros) Consumo del resumen worst-day del panel
# (micronutrients.build_micronutrient_report → per_day_floors): un plan que cumple los pisos EN PROMEDIO
# pero con un día individual <60% del piso en ≥2 micros accionables marca banner honesto (banner-only,
# jamás retry — corre fuera del grafo). Thresholds en micronutrients (MEALFIT_MICRO_PERDAY_RATIO/_MIN_MICROS).
MICRO_PERDAY_DEGRADE_ENABLED = _env_bool("MEALFIT_MICRO_PERDAY_DEGRADE", True)
# [P1-MICRO-WORSTDAY-EXCLUDE-UNREACHABLE · 2026-07-08] (plan vivo 9b6a43f6: macro-perfecto band 0.833 pero
# marcado _quality_degraded por worst_day=[vit_e, omega3]) los fat-micros estructuralmente difíciles de
# alimentos enteros (omega-3 exige mucho pescado/linaza; vit E nueces/aceites; vit D sol/suplemento) — ya
# cubiertos por la tarjeta de suplementación + el fatswap/seed hacen su mejor esfuerzo determinista — NO
# deben marcar "degradado" un plan por lo demás sólido (el banner asustaba por algo nutricionalmente
# inevitable). Se excluyen del trigger del worst-day; si quedan micros CERRABLES cortos (fibra/Ca/hierro),
# el banner sigue. Rollback: =false (todos disparan). tooltip-anchor: P1-MICRO-WORSTDAY-EXCLUDE-UNREACHABLE
MICRO_WORSTDAY_EXCLUDE_UNREACHABLE = _env_bool("MEALFIT_MICRO_WORSTDAY_EXCLUDE_UNREACHABLE", True)
_MICRO_WORSTDAY_EXCLUDE = ("vit_d_mcg", "omega3_g", "vit_e_mg")
# [P2-AUDIT-V5-BATCH · 2026-07-02] (GAP-M2) Targeting per-día del micro-closer — el follow-up que
# P1-MICRO-PERDAY-FLOOR declaró explícitamente: los micros "low" del worst-day flaggeado entran al
# set de floors del closer (el loop per-día interno solo escala los DÍAS deficientes). Nace OFF por
# el playbook medir→actuar: la serie del banner `micro_worst_day` (knob de arriba, ON) dimensiona
# la frecuencia real antes del flip. NO baja los umbrales 0.6/≥2 del detector.
# [P1-GATES-FLIP-ON · 2026-07-03] (audit v6 · P1-4) OFF→ON con serie del gym baseline: 9/20 planes
# con worst-day floor flaggeado (el eje micros es el más débil: mean 57.5) — el closer per-día tiene
# trabajo real y NO es gate (determinista, kcal/UL-bounded, renal-skip) → cero riesgo de retry.
MICRO_CLOSER_PERDAY_ENABLED = _env_bool("MEALFIT_MICRO_CLOSER_PERDAY", True)


def _protein_gkg_ceiling(goal) -> float:
    """[P3-PROTEIN-CEILING-GOAL-AWARE] Techo de proteína entregada (g/kg) por objetivo: déficit/
    pérdida de grasa → más alto (preservación muscular); volumen/mantenimiento → 2.2."""
    g = str(goal or "").strip().lower()
    is_cut = any(t in g for t in ("lose_fat", "lose_weight", "fat_loss", "deficit", "déficit",
                                  "perdida", "pérdida", "cut", "definir", "adelgaz"))
    return PROTEIN_GKG_CEILING_CUT if is_cut else PROTEIN_GKG_CEILING_DEFAULT


def _weight_kg_from_form(form_data: dict) -> float:
    """Peso en kg desde form_data (convierte lb→kg). 0.0 si ausente/no parseable."""
    try:
        w = float(form_data.get("weight") or 0)
        unit = str(form_data.get("weightUnit") or "kg").strip().lower()
        return w / 2.20462 if unit in ("lb", "lbs") else w
    except (TypeError, ValueError):
        return 0.0


def _renal_weight_basis_kg(form_data: dict) -> float:
    """[P2-RENAL-ADJUSTED-WEIGHT · 2026-06-19] (audit fresco P2-5) Base de peso para el CAP RENAL de proteína.
    KDIGO usa peso AJUSTADO/ideal en obesidad (IMC>30), no el peso real. Gateado por MEALFIT_RENAL_ADJUSTED_WEIGHT
    (default OFF → peso real, comportamiento actual). OFF / sin height / IMC≤30 → peso real (fail-safe). IBW por
    Devine; ajustado = IBW + 0.4×(real−IBW), clamp [IBW, real] (nunca sobre el real ni bajo el ideal). Solo lo
    consumen los 3 callsites del cap renal — el resto del código sigue con `_weight_kg_from_form`."""
    wkg = _weight_kg_from_form(form_data)
    if not RENAL_ADJUSTED_WEIGHT_ENABLED or wkg <= 0 or not isinstance(form_data, dict):
        return wkg
    try:
        h_cm = float(form_data.get("height") or 0)
        if h_cm <= 0:
            return wkg
        bmi = wkg / ((h_cm / 100.0) ** 2)
        if bmi <= 30.0:
            return wkg  # solo ajusta en obesidad (donde real vs ideal diverge materialmente)
        h_in = h_cm / 2.54
        male = str(form_data.get("gender") or "").strip().lower() in ("male", "masculino", "masculina", "hombre", "m")
        ibw = (50.0 if male else 45.5) + 2.3 * max(0.0, h_in - 60.0)
        adjusted = ibw + 0.4 * (wkg - ibw)
        return max(ibw, min(wkg, adjusted))
    except (TypeError, ValueError):
        return wkg


def _goal_aware_trim_ceiling_pct(form_data: dict, target_protein_day: float) -> float:
    """[P3-PROTEIN-CEILING-GOAL-AWARE] `ceiling_pct` para el trim = techo_g/kg × peso / target.
    Robusto a peso ausente: fallback por objetivo (déficit más laxo, volumen estricto).
    [P3-CONDITION-RULES] ERC: el techo g/kg es 0.8 (KDIGO 2024), NO el alto goal-aware — invierte
    la regla para que el trim baje la proteína a nivel renal en vez de protegerla alta."""
    renal = CONDITION_RULES_ENABLED and isinstance(form_data, dict) and _is_renal_condition(form_data)
    goal = form_data.get("mainGoal") if isinstance(form_data, dict) else None
    # [P1-RENAL-DIALYSIS-STAGING] techo renal estadificado por diálisis (1.2) vs no-diálisis (0.8).
    gkg = _renal_protein_gkg_for_profile(form_data) if renal else _protein_gkg_ceiling(goal)
    # [P2-RENAL-TRIM-WEIGHT-BASIS · 2026-06-19] (audit fresco P2-5) El cap renal usa `_renal_weight_basis_kg`
    # (peso ajustado IBW Devine en obesidad cuando MEALFIT_RENAL_ADJUSTED_WEIGHT=ON); el trim-ceiling usaba el
    # peso REAL → con el knob ON + renal obeso, el techo del trim quedaba más laxo que el cap (inconsistencia
    # latente). Comparten ahora la misma base. Default OFF → `_renal_weight_basis_kg` devuelve el peso real → cero
    # cambio de comportamiento.
    if renal and isinstance(form_data, dict):
        wkg = _renal_weight_basis_kg(form_data)
    else:
        wkg = _weight_kg_from_form(form_data) if isinstance(form_data, dict) else 0.0
    if wkg > 0 and target_protein_day and target_protein_day > 0:
        return max(1.0, min(1.30, (gkg * wkg) / target_protein_day))
    if renal:
        return 1.0  # ERC sin peso parseable → techo estricto al target (ya capeado aguas arriba)
    return 1.18 if gkg >= 2.5 else 1.08  # sin peso → fallback por objetivo

# [P2-ANTI-REPETITION-TOLERANCE · 2026-06-13] Tolerancia de platos repetidos vs los
# últimos 3 planes ANTES de rechazar+reintentar. Pre-fix era tolerancia CERO: 1 solo
# plato repetido (de ~12) forzaba 3 reintentos → entrega degradada + alerta, aunque el
# plan fuera médicamente sano y con buenos macros. Algo de solape entre planes es
# natural (la gente tiene comidas favoritas). Default 2: hasta 2 repetidos = OK; 3+ =
# rechazo legítimo por falta de variedad. Subir a 0 revierte al comportamiento estricto.
ANTI_REPETITION_TOLERANCE = _env_int("MEALFIT_ANTI_REPETITION_TOLERANCE", 2)


def _meal_macro_num(x) -> float:
    """Parsea un valor de macro/caloría a float, tolerando "154g", "464 kcal", None.
    [P2-PERSIST-NAN-GUARD · 2026-06-13] Coacciona NaN/Inf → 0.0 (sin import math:
    `v == v` detecta NaN, comparación detecta Inf) para que un no-finito no se propague
    al solver/balancing ni al INSERT — Postgres jsonb rechaza NaN/Infinity y perdería el plan."""
    try:
        s = str(x).strip().lower().replace("g", "").replace("kcal", "").strip()
        v = float(s) if s else 0.0
        return v if (v == v and v not in (float("inf"), float("-inf"))) else 0.0
    except Exception:
        return 0.0


def _protein_floor_shortfall(plan, *, renal_capped: bool, form_data: dict = None):
    """[P3-PROTEIN-FLOOR / P2-PROTEIN-FLOOR-FAILHARD · 2026-06-21] Días bajo el piso de
    proteína (HARD_PCT × target diario). SSOT compartido por `review_plan_node` (gate de
    retry, severity 'high') y `_apply_critical_review_guardrails` (backstop fail-hard al
    finalizar). Devuelve lista de (day_label, protein_g, target_g); vacía si cumple, está
    exento (renal o gate off), o no hay target válido.

    Mide la proteína DECLARADA por comida (`_meal_macro_num`) — la MISMA medida que usa el
    gate de review. [P2-FALLBACK-PHYSICAL-MACROS · 2026-07-01] Los macros del fallback ahora
    son FÍSICOS (plantillas reescaladas + truth-up), no target×ratio asertado — un fallback
    podría medir bajo el piso, pero NUNCA se re-verifica: el backstop fail-hard está gateado
    por `not already_fallback` (cero riesgo de loop de sustitución).
    Tooltip-anchor: P2-PROTEIN-FLOOR-FAILHARD."""
    if not PROTEIN_FLOOR_HARD_GATE or renal_capped or not isinstance(plan, dict):
        return []
    try:
        import re as _re_pf
        _tgt_p = None
        _macros = plan.get("macros")
        if isinstance(_macros, dict):
            _mp = _re_pf.search(r"(\d+)", str(_macros.get("protein", "")))
            if _mp:
                _tgt_p = float(_mp.group(1))
        if not _tgt_p or _tgt_p <= 0:
            return []
        # [P3-BARIATRIC-PROTEIN-FLOOR-RELAX · 2026-06-28] Piso bariátrico relajado (el pouch limita la ingesta; el
        # target ya está capeado a 80g — 90% es inviable en comidas diminutas/dulces y rompe grasa/kcal al forzarlo).
        _pct = PROTEIN_FLOOR_HARD_PCT
        try:
            from constants import BARIATRIC_CONDITION_TERMS as _BT_PF
            if form_data and any(any(_t in _c for _t in _BT_PF) for _c in _condition_strings(form_data)):
                _pct = PROTEIN_FLOOR_HARD_PCT_BARIATRIC
        except Exception:
            pass
        _short = []
        for _i, _day in enumerate(plan.get("days", []) or [], 1):
            _dp = sum(_meal_macro_num(_mm.get("protein")) for _mm in (_day.get("meals", []) or []))
            if _dp < _pct * _tgt_p:
                _short.append((_day.get("day", _i), round(_dp), round(_tgt_p)))
        return _short
    except Exception as _pf_e:
        logger.warning(f"[P3-PROTEIN-FLOOR] cálculo de shortfall falló: {type(_pf_e).__name__}: {_pf_e}")
        return []


def _shopping_list_completeness(plan, form_data):
    """[P2-SHOPPING-COMPLETENESS · 2026-06-21] Mide si la lista de compras es suficientemente
    completa para la duración del ciclo. Devuelve {days, distinct, expected_min, is_empty, is_sparse}.

    - distinct: alimentos DISTINTOS en `aggregated_shopping_list` (excluye los "🚨 urgentes",
      que son supplement post-hoc, no la lista base).
    - expected_min: piso escalado por semanas del ciclo (base + (weeks-1)×per_week, capeado).
      Conservador a propósito: la VARIEDAD de alimentos NO escala linealmente con los días — un
      plan de 30d reusa ingredientes y compra MÁS cantidad, no necesariamente más distintos. Por
      eso el incremento por semana es pequeño y hay tope (evita falsos "escasos").
    - is_empty: el plan TIENE recetas con ingredientes pero la lista salió con 0 alimentos (bug
      del builder o drop total). Señal DURA.
    - is_sparse: 0 < distinct < expected_min (señal SUAVE; los gates de variedad del plan ya
      cubren la mayoría). Tooltip-anchor: P2-SHOPPING-COMPLETENESS."""
    _days_map = {"weekly": 7, "biweekly": 15, "monthly": 30}
    days = _days_map.get(str((form_data or {}).get("groceryDuration") or "weekly").lower(), 7)
    agg = (plan.get("aggregated_shopping_list") if isinstance(plan, dict) else None) or []
    names = set()
    for _it in agg:
        if not isinstance(_it, dict):
            continue
        _cat = str(_it.get("category") or _it.get("display_category") or "").lower()
        if "urgente" in _cat:
            continue
        _nm = str(_it.get("name") or _it.get("display_name") or "").strip().lower()
        if _nm:
            names.add(_nm)
    distinct = len(names)
    _has_ingredients = False
    if isinstance(plan, dict):
        for _d in (plan.get("days") or []):
            for _m in (_d.get("meals") or []):
                if _m.get("ingredients"):
                    _has_ingredients = True
                    break
            if _has_ingredients:
                break
    weeks = max(1, round(days / 7))
    expected_min = min(
        SHOPPING_MIN_DISTINCT_CAP,
        SHOPPING_MIN_DISTINCT_BASE + (weeks - 1) * SHOPPING_MIN_DISTINCT_PER_WEEK,
    )
    return {
        "days": days,
        "distinct": distinct,
        "expected_min": expected_min,
        "is_empty": bool(_has_ingredients and distinct == 0),
        "is_sparse": bool(_has_ingredients and 0 < distinct < expected_min),
    }


_MEDICAL_NONE_SENTINELS = {
    "", "ninguna", "ninguno", "ningunas", "ningunos", "none", "n/a", "na",
    "no", "nada", "sin alergias", "sin condiciones", "ninguna alergia",
}


def _has_real_medical_flags(items) -> bool:
    """[P2-MEDICAL-FACTCHECK-GATE · 2026-06-13] True si `items` (lista o string del
    form) contiene alguna alergia/condición REAL, no el sentinel "Ninguna".

    El frontend manda `allergies=["Ninguna"]` cuando el usuario no tiene alergias →
    lista no-vacía → truthy → el gate `if allergies or medical_conditions` corría el
    fact-checking médico por-ingrediente (~40s de tool calls) inútilmente para usuarios
    sanos. Este helper filtra los sentinels. NO reduce rigor para quien SÍ tiene
    restricciones reales — solo evita investigar interacciones que no aplican. Anchor:
    P2-MEDICAL-FACTCHECK-GATE."""
    if not items:
        return False
    if isinstance(items, str):
        items = [items]
    try:
        return any(str(x).strip().lower() not in _MEDICAL_NONE_SENTINELS for x in items)
    except Exception:
        return bool(items)


# [P3-CONDITION-RULES · 2026-06-14] Detección determinista de las condiciones del set Pareto DR.
# Términos SIN acentos (se normalizan con strip_accents) y sobre-inclusivos: en seguridad clínica,
# un falso positivo (aplicar un cap conservador a quien no lo necesita) es preferible a un falso
# negativo (no detectar la condición). Anclaje regulatorio: DM2 + ERC = las 2 condiciones que
# Medicare MNT reembolsable cubre.
# Términos SSOT en constants.py — compartidos con prompts/plan_generator para que el detector del
# cap determinista y el de la directiva de prompt NUNCA driften (cierra P3-CONDITION-RULES review #3).
from constants import (RENAL_CONDITION_TERMS as _RENAL_CONDITION_TERMS,
                       DIABETES_CONDITION_TERMS as _DIABETES_CONDITION_TERMS)


def _condition_strings(form_data) -> list:
    """Lista normalizada (lower + sin acentos, sin sentinel 'Ninguna') de las condiciones
    médicas declaradas en el form. Base de toda regla determinista por condición."""
    if not isinstance(form_data, dict):
        return []
    try:
        from constants import strip_accents as _sa
    except Exception:
        _sa = lambda x: x  # noqa: E731 — degradación: sin normalizar acentos (los términos cubren variantes)
    raw = form_data.get("medicalConditions") or form_data.get("medical_conditions") or []
    if isinstance(raw, str):
        raw = [raw]
    out = []
    for c in raw:
        s = str(c).strip().lower()
        if not s or s in _MEDICAL_NONE_SENTINELS:
            continue
        try:
            s = _sa(s)
        except Exception:
            pass
        out.append(s)
    return out


def _is_renal_condition(form_data) -> bool:
    """[P3-CONDITION-RULES] True si el perfil declara ERC/enfermedad renal (gate KDIGO)."""
    return any(any(t in c for t in _RENAL_CONDITION_TERMS) for c in _condition_strings(form_data))


def _is_diabetes_condition(form_data) -> bool:
    """[P3-CONDITION-RULES] True si el perfil declara diabetes/prediabetes (regla ADA 2026)."""
    return any(any(t in c for t in _DIABETES_CONDITION_TERMS) for c in _condition_strings(form_data))


def _is_bariatric_condition(form_data) -> bool:
    """[P1-BARIATRIC-CRITICAL-RETRY · 2026-06-28] True si el perfil declara cirugía bariátrica (mismo SSOT de términos
    que cap_bariatric_portions). Fail-safe: import roto → False (no degrada el crítico, va a fallback)."""
    try:
        from constants import BARIATRIC_CONDITION_TERMS as _BT
    except Exception:
        return False
    return any(any(t in c for t in _BT) for c in _condition_strings(form_data))


def _cap_macros_dict_renal(md, cap_g: float, reassign_to: str):
    """[P3-CONDITION-RULES] Capea la proteína de un dict de macros (`{protein_g/_str, ...}`) al
    cap renal in place y reasigna las kcal liberadas a grasa (diabético) o carbo (iso-calórico).
    Retorna la proteína original (g) si capeó, None si ya estaba ≤ cap. Mantiene `_g` y `_str`."""
    if not isinstance(md, dict):
        return None
    p = _meal_macro_num(md.get("protein_g") if md.get("protein_g") is not None else md.get("protein_str"))
    if p <= cap_g:
        return None
    freed = (p - cap_g) * 4.0  # proteína = 4 kcal/g
    icap = int(round(cap_g))
    md["protein_g"] = icap
    md["protein_str"] = f"{icap}g"
    if reassign_to == "fat":
        f = _meal_macro_num(md.get("fats_g") if md.get("fats_g") is not None else md.get("fats_str"))
        nf = int(round(f + freed / 9.0))
        md["fats_g"] = nf; md["fats_str"] = f"{nf}g"
    else:
        c = _meal_macro_num(md.get("carbs_g") if md.get("carbs_g") is not None else md.get("carbs_str"))
        nc = int(round(c + freed / 4.0))
        md["carbs_g"] = nc; md["carbs_str"] = f"{nc}g"
    return int(round(p))


def _renal_reassign_macro(active_macros: dict, cap_g: int, old_p: float, diabetic: bool, mirror) -> str:
    """[P2-14-RENAL-REASSIGN · 2026-06-16] (gap-audit P2-14) Dedup VERBATIM del reassign renal de proteína
    que estaba triplicado inline en `_apply_deterministic_clinical_layer` y `assemble_plan_node` (SITES B/C).
    Capea `protein_str` a `cap_g` y reasigna las kcal liberadas: a GRASA si diabético (comorbilidad
    diabético-nefropatía: NO subir la carga glucémica con carbo) o a CARBO iso-kcal (swap 1:1 g, ambos
    4 kcal/g) si no. Escribe `active_macros` (claves *_str) y, si no es None, el dict espejo `mirror`
    (claves SIN sufijo: protein/fats/carbs). El caller pasa `mirror` YA copiado (anti-aliasing) — el helper
    NO copia. Usa round() (NO int(round()) como SITE A) por equivalencia byte con los inline B/C. Retorna
    'fat'|'carb'. NO cambia la política carb-vs-fat (decisión clínica diferida a nutricionista). Anchor: P2-14-RENAL-REASSIGN."""
    _freed = (old_p - cap_g) * 4.0  # proteína = 4 kcal/g
    active_macros["protein_str"] = f"{cap_g}g"
    if mirror is not None:
        mirror["protein"] = f"{cap_g}g"
    if diabetic:
        _old_f = _meal_macro_num(active_macros.get("fats_str"))
        _new_f = round(_old_f + _freed / 9.0)
        active_macros["fats_str"] = f"{_new_f}g"
        if mirror is not None:
            mirror["fats"] = f"{_new_f}g"
        return "fat"
    _old_c = _meal_macro_num(active_macros.get("carbs_str"))
    _new_c = round(_old_c + (old_p - cap_g))  # swap proteína→carbo iso-kcal (1:1 g)
    active_macros["carbs_str"] = f"{_new_c}g"
    if mirror is not None:
        mirror["carbs"] = f"{_new_c}g"
    return "carb"


def _apply_renal_cap_to_nutrition(nutrition: dict, form_data: dict) -> None:
    """[P3-CONDITION-RULES · 2026-06-14] CAP RENAL EN LA FUENTE. Capea el target de proteína de
    `nutrition` (KDIGO ~0.8 g/kg) ANTES de que fluya al skeleton/generación/review/fallback. Es el
    fix raíz del modo de fallo hallado en la prueba en vivo: con el target a 2.2 g/kg, el LLM
    generaba un plan alto en proteína, el revisor médico renal-aware lo RECHAZABA críticamente
    ('carga proteica excesiva para ERC') y caía a un fallback matemático SIN capear. Capeando el
    target aquí, el LLM genera un plan renal-apropiado que el revisor aprueba, y el fallback (que
    se construye desde `nutrition.macros.protein_g`) también queda capeado. Mutates `nutrition`.
    Diabético-nefropatía: reasigna a grasa (no carbo). Fail-safe — no aplica si no hay peso."""
    if not (CONDITION_RULES_ENABLED and isinstance(nutrition, dict) and _is_renal_condition(form_data)):
        return
    try:
        wkg = _renal_weight_basis_kg(form_data)   # [P2-RENAL-ADJUSTED-WEIGHT · 2026-06-19] (P2-5) peso ajustado en obesidad
        if wkg <= 0:
            return
        _gkg = _renal_protein_gkg_for_profile(form_data)  # [P1-RENAL-DIALYSIS-STAGING] 1.2 diálisis / 0.8 no
        cap_g = round(_gkg * wkg)
        if cap_g <= 0:
            return
        diabetic = _is_diabetes_condition(form_data)
        reassign = "fat" if diabetic else "carb"
        was = None
        for key in ("macros", "total_daily_macros"):
            w = _cap_macros_dict_renal(nutrition.get(key), cap_g, reassign)
            if w:
                was = w
        if was:
            nutrition["renal_protein_cap"] = {
                "applied": True, "gkg": _gkg, "protein_g": cap_g,
                "was_g": was, "weight_kg": round(wkg, 1),
                "guideline": ("KDIGO 2024 (diálisis 1.0-1.2 g/kg)" if _gkg >= 1.0
                              else "KDIGO 2024 (G3-G5 no-diálisis 0.8 g/kg)"), "reassigned_to": reassign,
                "comorbid_diabetes": bool(diabetic), "source": "nutrition_target",
            }
            logger.warning(
                f"🫘 [P3-CONDITION-RULES] ERC: target de proteína capeado en la FUENTE {was}g→{cap_g}g "
                f"(~{_gkg} g/kg × {wkg:.1f}kg), kcal a {reassign}"
                f"{' (DM2)' if diabetic else ''}. Fluye a generación/review/fallback.")
    except Exception as _rcn_e:
        logger.warning(f"[P3-CONDITION-RULES] cap renal en la fuente falló: "
                       f"{type(_rcn_e).__name__}: {_rcn_e}")


# [P3-CONDITION-ENGINE] Captura el prefijo de cantidad de un ingrediente ("100g de ", "2 lonjas de ",
# "0.5 taza de ") para preservarlo al sustituir → la lista de compras conserva el peso y el coherence
# guard sigue cuadrando. Sin prefijo (condimentos "al gusto") el sustituto queda sin cantidad (OK).
_COND_SUB_QTY_PREFIX_RE = _re.compile(
    r"^\s*(\d[\d.,/]*\s*[a-záéíóúñ]*\.?\s*(?:de\s+)?)", _re.IGNORECASE)


# [P1-SUBST-RECIPE-REWRITE · 2026-06-28] Tokens que NO se usan para localizar el ingrediente viejo en los pasos:
# texturas/preparaciones culinarias (un paso "forma una crema suave" NO debe reescribirse si el sub fue
# 'crema de leche'→yogurt), básicos casi-ubicuos (agua/sal/aceite) y preposiciones/unidades. Conservador: ante la
# duda, no reescribir (preferimos dejar una mención que corromper prosa legítima — hallazgo de la review adversaria).
_SUBST_REWRITE_SKIP_TOKENS = frozenset({
    "crema", "masa", "salsa", "caldo", "base", "punto", "leche", "agua", "aceite", "sal", "sugar",
    "de", "del", "con", "sin", "para", "una", "uno", "los", "las", "the",
    "gramos", "gramo", "taza", "tazas", "cucharada", "cucharadas", "cda", "cdas", "cdta", "cucharadita",
    "onza", "onzas", "libra", "libras", "lonja", "lonjas", "pedazo", "pedazos", "vaso", "vasos",
    "cubito", "cubitos", "lata", "latas", "botella", "pizca", "ramita", "diente", "dientes",
    "unidad", "unidades",
})

_SUBST_ARTICLE_RE_BODY = r"(?:\b(?:el|la|los|las|un|una|unos|unas)\s+)?\b"


def _accent_loose_body(tok: str) -> str:
    """Convierte un token normalizado en cuerpo regex insensible a acentos: 'azucar' → 'az[uúü]car'.
    Cierra el bug donde el paso dice 'azúcar' (con tilde) pero el token buscado era 'azucar' (sin)."""
    _vmap = {"a": "[aá]", "e": "[eé]", "i": "[ií]", "o": "[oó]", "u": "[uúü]", "n": "[nñ]", "c": "[cç]"}
    return "".join(_vmap.get(ch, _re.escape(ch)) for ch in tok)


def _strip_qty_prefix_for_step(s: str) -> str:
    """Nombre del ingrediente sin cantidad/unidad, para insertarlo en un paso. '100g de pollo' → 'pollo';
    'Stevia al gusto' → 'Stevia al gusto'. Fail-safe (devuelve el original si no matchea)."""
    try:
        m = _re.match(r"^\s*[\d.,/]+\s*[a-záéíóúñ]*\.?\s*(?:de\s+)?(.+)$", str(s), _re.IGNORECASE)
        return (m.group(1).strip() if m else str(s)).strip()
    except Exception:
        return str(s)


def _rewrite_recipe_steps_after_subs(meal: dict, token_subs: list) -> bool:
    """[P1-SUBST-RECIPE-REWRITE · 2026-06-28] Reescribe menciones del ingrediente sustituido en los PASOS de la receta.
    `token_subs`: lista de (tokens_busqueda: list[str], nombre_nuevo: str). Diseño verificado por review adversaria:
    acento-tolerante (matchea 'azúcar' aunque el token sea 'azucar'), ELIMINA el artículo previo (evita 'la aceite'),
    salta texturas culinarias (no toca 'forma una crema suave'), longest-token-first (no parte multi-palabra), `\\b`
    exacto + plural opcional (no `\\w*` que tragaba 'cremoso'). Determinista, idempotente (post-fix el token viejo ya no
    está), fail-safe. NO toca ingredients ni macros (solo `meal['recipe']`). Devuelve True si cambió algún paso."""
    rec = meal.get("recipe")
    steps = list(rec) if isinstance(rec, list) else ([] if rec is None else [str(rec)])
    if not steps or not token_subs:
        return False
    try:
        from constants import strip_accents as _sa_steps_note
    except Exception:
        def _sa_steps_note(x):
            return x
    pats = []  # (compiled_pattern, new_display) ordenados por longitud de token DESC
    _seen = set()
    for tokens, new in token_subs:
        new_disp = _strip_qty_prefix_for_step(new)
        for tok in sorted({str(t).strip().lower() for t in (tokens or []) if t}, key=len, reverse=True):
            if len(tok) < 4 or tok in _SUBST_REWRITE_SKIP_TOKENS:
                continue
            if tok in _seen:
                continue
            _seen.add(tok)
            try:
                pat = _re.compile(_SUBST_ARTICLE_RE_BODY + _accent_loose_body(tok) + r"(?:es|s)?\b", _re.IGNORECASE)
            except Exception:
                continue
            pats.append((len(tok), pat, new_disp))
    if not pats:
        return False
    pats.sort(key=lambda x: x[0], reverse=True)
    changed = False
    out = []
    for st in steps:
        s = str(st)
        # [P2-SUBST-NOTE-PROVENANCE · 2026-07-06] las notas "se reemplazó X por Y" citan el
        # alimento ORIGINAL a propósito — reescribirlas rompe la procedencia ("se reemplazó
        # el proteína crudo", batido cd4ae3c3). Exentas del replace; el resto de notas
        # deterministas (💪 closer de proteína) SÍ deben seguir al swap.
        if "se reemplaz" in _sa_steps_note(s.lower()):
            out.append(s)
            continue
        for _ln, pat, new_disp in pats:
            def _rep(m, _nd=new_disp):
                # descapitaliza salvo inicio de paso (preserva prosa es-DO: "vierte stevia", no "vierte Stevia")
                return (_nd[:1].upper() + _nd[1:]) if m.start() == 0 else (_nd[:1].lower() + _nd[1:])
            s2 = pat.sub(_rep, s)
            if s2 != s:
                s = _re.sub(r"\s{2,}", " ", s2).strip()
                changed = True
        out.append(s)
    if changed:
        meal["recipe"] = out
    return changed


def _apply_substitutions_core(plan: dict, subs: list, note_builder, note_sentinel: str,
                              on_meal_fixed=None) -> int:
    """[P0-ALLERGEN-SUBS · 2026-06-14] Motor de swap determinista COMPARTIDO por las sustituciones
    por condición (DM2/HTA/dislipidemia) y por alérgeno IgE. `subs`: lista de dicts
    {tokens, replacement, label, negatives, condition, preserve_qty} (de `collect_substitutions` o
    `collect_allergen_substitutions`). `note_builder(uniq_labels, conds) -> str`: la nota es-DO
    inyectada a la receta; `note_sentinel`: substring para la guarda de idempotencia de la nota.
    `on_meal_fixed(meal, uniq_labels, conds)`: callback opcional para flags por-llamador.

    PRESERVA el prefijo de cantidad (staples) → la lista de compras conserva el peso comprable y el
    coherence guard sigue cuadrando. RECOMPUTA los macros del plato por DELTA quirúrgico (fail-safe:
    si la DB no resuelve AMBOS strings, deja los macros previos). Idempotente. Mutates `plan`.
    Retorna #comidas afectadas. Extraído verbatim de `_apply_condition_substitutions` (P3-CONDITION-
    ENGINE) para reusar el motor sin drift entre los dos llamadores."""
    if not subs:
        return 0
    try:
        from constants import strip_accents as _sa
    except Exception:
        _sa = lambda x: x  # noqa: E731
    try:
        from nutrition_db import IngredientNutritionDB
        _db = IngredientNutritionDB()
    except Exception:
        _db = None

    def _match(ing_norm):
        for s in subs:
            if any(neg in ing_norm for neg in s["negatives"]):
                continue
            if any(t in ing_norm for t in s["tokens"]):
                return s
        return None

    def _sub_string(orig, replacement, preserve_qty):
        # Staples (preserve_qty): preserva el prefijo de cantidad ("100g de", "2 lonjas de") + el
        # reemplazo → la lista de compras conserva el peso comprable. Condimentos/azúcares: deja el
        # reemplazo bare (queda "al gusto"); preservar el prefijo dejaría la palabra ofensora ("cubito").
        if preserve_qty:
            m = _COND_SUB_QTY_PREFIX_RE.match(str(orig)) if _COND_SUB_QTY_PREFIX_RE else None
            if m and m.group(1).strip():
                return m.group(1) + replacement
        return replacement

    fixed = 0
    for day in plan.get("days", []) or []:
        for meal in day.get("meals", []) or []:
            labels, conds, changed = [], set(), False
            swaps = []  # (string_viejo, string_nuevo) — solo de la lista canónica, para el delta de macros
            recipe_token_subs = []  # (tokens_busqueda, nombre_nuevo) — para reescribir los pasos (P1-SUBST-RECIPE-REWRITE)
            for key in ("ingredients", "ingredients_raw"):
                ings = meal.get(key)
                if not isinstance(ings, list):
                    continue
                out = []
                for ing in ings:
                    s = _match(_sa(str(ing).lower()))
                    if s:
                        new = _sub_string(ing, s["replacement"], s.get("preserve_qty"))
                        # [P2-SUBS-DEDUP-QTY · 2026-06-15] Dedup SOLO condimentos bare (preserve_qty
                        # False: 'Stevia al gusto' ×2 = ruido). Los staples con cantidad (preserve_qty
                        # True) SE CONSERVAN aunque dos ofensores mapeen al mismo reemplazo
                        # (salami+longaniza→2×pollo): el aggregator suma las cantidades → preserva el
                        # peso comprable Y el delta de macros (2×pollo) cuadra con la lista. Antes el
                        # dedup colapsaba a 1×pollo → media comida + macros inflados (bug del audit P2).
                        if s.get("preserve_qty") or new not in out:
                            out.append(new)
                        if key == "ingredients":
                            swaps.append((str(ing), new))
                            recipe_token_subs.append((s.get("tokens") or [], new))
                        labels.append(s["label"]); conds.add(s["condition"]); changed = True
                    else:
                        out.append(ing)
                meal[key] = out
            if changed:
                # Ajusta los macros del plato por DELTA quirúrgico: macros(nuevo) - macros(viejo) SOLO de
                # los ingredientes sustituidos → el header deja de describir el ingrediente viejo sin
                # tocar (ni perder por 0-silencioso) la contribución del resto del plato. Fail-safe: si
                # un string no resuelve, ese sumando es 0 (conservador). Mismo patrón que el quantize.
                if _db is not None and swaps:
                    try:
                        _d = {"protein": 0.0, "carbs": 0.0, "fats": 0.0, "kcal": 0.0}
                        _touched = False
                        for _old, _new in swaps:
                            _om = _db.macros_from_ingredient_string(_old) or {}
                            _nm = _db.macros_from_ingredient_string(_new) or {}
                            # [review adversaria P4] AMBOS deben resolver para aplicar el delta. Si solo
                            # uno resuelve, el delta sería asimétrico: reemplazo no-resuelve → resta el
                            # viejo y suma 0 (pierde proteína, re-introduce el "0 silencioso"); viejo
                            # no-resuelve → suma el nuevo sin restar (infla). En ambos casos dejamos los
                            # macros intactos (conservador) — la sustitución textual + cantidad ya pasó.
                            if _om and _nm:
                                _touched = True
                                for _k in _d:
                                    _d[_k] += (_nm.get(_k) or 0.0) - (_om.get(_k) or 0.0)
                        if _touched and any(_d.values()):
                            meal["protein"] = max(0, round(_meal_macro_num(meal.get("protein")) + _d["protein"]))
                            meal["carbs"] = max(0, round(_meal_macro_num(meal.get("carbs")) + _d["carbs"]))
                            meal["fats"] = max(0, round(_meal_macro_num(meal.get("fats")) + _d["fats"]))
                            meal["cals"] = max(0, round(_meal_macro_num(meal.get("cals")) + _d["kcal"]))
                            meal["macros"] = [f"P:{meal['protein']}g", f"C:{meal['carbs']}g", f"G:{meal['fats']}g"]
                    except Exception:
                        pass
                # [P1-SUBST-RECIPE-REWRITE · 2026-06-28] Reescribe las menciones del ingrediente VIEJO en los pasos de la
                # receta ANTES de la nota (para que la nota siga siendo la última línea). Solo usa los tokens de la lista
                # canónica `ingredients` (recipe_token_subs). Fail-safe: si falla, los pasos quedan intactos.
                if SUBST_RECIPE_REWRITE_ENABLED and recipe_token_subs:
                    try:
                        _rewrite_recipe_steps_after_subs(meal, recipe_token_subs)
                    except Exception:
                        pass
                uniq = sorted(set(labels))
                note = note_builder(uniq, conds)
                rec = meal.get("recipe")
                if not isinstance(rec, list):
                    rec = [] if rec is None else [str(rec)]
                if note and not any(note_sentinel in str(s) for s in rec):
                    meal["recipe"] = rec + [note]
                if on_meal_fixed:
                    try:
                        on_meal_fixed(meal, uniq, conds)
                    except Exception:
                        pass
                fixed += 1
    return fixed


def _apply_condition_substitutions(plan: dict, form_data: dict) -> int:
    """[P3-CONDITION-ENGINE · 2026-06-14] Guard determinista de SUSTITUCIÓN de ingredientes por
    condición (patrón food-safety GENERALIZADO, dirigido por el registro `condition_rules`). Para
    CADA condición activa sustituye los ingredientes contraindicados por una alternativa segura en
    `ingredients`+`ingredients_raw` ANTES del review+shopping: DM2 → azúcar añadida→stevia/agua; HTA
    → embutidos/cubitos/bacalao salado→fresco. El plan queda clínicamente mejor Y deja de gatillar
    el rechazo del revisor. Reusa `_apply_substitutions_core` (motor compartido con los alérgenos).

    PRESERVA el prefijo de cantidad del ingrediente original ("100g de longaniza" → "100g de Pechuga
    de pollo") → la lista conserva el peso comprable. RECOMPUTA macros por delta (fail-safe).
    Idempotente. Mutates `plan`. Retorna #comidas."""
    if not CONDITION_RULES_ENABLED:
        return 0
    try:
        from condition_rules import collect_substitutions
        # [P2-13] diet-aware: redirige reemplazos animales a vegetal/pescado para veg* (gated por DIET_HARD_GUARD)
        subs = collect_substitutions(
            form_data,
            diet_type=_canonicalize_diet_type(form_data.get("dietType")) if DIET_HARD_GUARD else None)
    except Exception:
        subs = []

    def _note(uniq, conds):
        return (f"⚕️ Ajuste clínico (condición médica): se sustituyó {', '.join(uniq)} por una "
                f"alternativa segura (sin azúcar añadida / baja en sodio) para tu condición.")

    def _flags(meal, uniq, conds):
        meal["_condition_subs_fixed"] = uniq
        if "dm2" in conds:
            meal["_dm2_sugar_fixed"] = uniq  # flag de compatibilidad hacia atrás

    return _apply_substitutions_core(plan, subs, _note, "Ajuste clínico", _flags)


def _apply_allergen_substitutions(plan: dict, form_data: dict) -> int:
    """[P0-ALLERGEN-SUBS · 2026-06-14] Sustitución QUIRÚRGICA de alérgenos IgE DECLARADOS
    (`form_data['allergies']`) por una alternativa segura que RESUELVE al catálogo, ANTES del review.
    Cierra el gap del audit clínico: las alergias dependían del prompt + el backstop romo
    `_scan_allergen_violations` (que nukea el plan entero a fallback). Aquí el swap es in-place
    (preserva cantidad + macros por delta, vía el motor compartido) y conserva el plan rico del LLM;
    `_scan_allergen_violations` (review) sigue escalando cualquier RESIDUAL a crítico → cero
    regresión de seguridad. Solo fish/shellfish/soy/gluten (lácteos/huevo/maní/frutos secos NO tienen
    target libre del alérgeno que resuelva en el catálogo es-DO → siguen por el path crítico→fallback).
    Mutates `plan`. Retorna #comidas afectadas."""
    if not ALLERGEN_SUBSTITUTION_ENABLED:
        return 0
    try:
        from condition_rules import collect_allergen_substitutions
        # [P2-13] diet-aware: redirige el reemplazo animal (pollo) a vegetal/pescado para veg*
        subs = collect_allergen_substitutions(
            form_data,
            diet_type=_canonicalize_diet_type(form_data.get("dietType")) if DIET_HARD_GUARD else None)
    except Exception:
        subs = []

    def _note(uniq, conds):
        return (f"🛡️ Sustitución por alergia declarada: se reemplazó {', '.join(uniq)} por una "
                f"alternativa segura libre del alérgeno. Verifica igualmente las etiquetas de lo que compras.")

    def _flags(meal, uniq, conds):
        meal["_allergen_subs_fixed"] = uniq

    return _apply_substitutions_core(plan, subs, _note, "Sustitución por alergia", _flags)


# [C2-ALLERGEN-GUARD · 2026-06-13] Mapa de sinónimos de alérgenos comunes (es-DO) → términos
# que pueden aparecer en los ingredientes. Sesgo a SOBRE-detectar: para alérgenos, un falso
# positivo (rechazar un plan seguro) es MUCHO mejor que un falso negativo (servir el alérgeno).
# [P1-ALLERGEN-DERIVATIVES · 2026-06-14] Extensión con DERIVADOS / ingredientes compuestos por
# categoría (whey/caseína/helado para lácteos; mayonesa/merengue/holandesa para huevo;
# miso/tempeh/teriyaki/lecitina para soya; cuscús/seitán/malta/sémola para gluten; anchoa/surimi/
# salsa inglesa para pescado; mazapán/nutella/praliné para frutos secos). Cierra el punto ciego
# del audit: el alérgeno escondido en un compuesto (whey en un batido, mayonesa en un aderezo)
# antes solo dependía del revisor LLM (falible). Es DETECCIÓN (backstop _scan_allergen_violations
# + filtro de candidatos del closer), no sustitución → no requiere filas de catálogo nuevas y
# preserva el sesgo de sobre-detección intencional. Anchor: P1-ALLERGEN-DERIVATIVES.
_ALLERGEN_SYNONYMS = {
    "mani": ["mani", "cacahuate", "peanut", "mantequilla de mani", "crema de mani",
             "salsa de mani"],
    "frutos secos": ["almendra", "almendras", "nuez", "nueces", "maranon", "pistacho",
                     "avellana", "merey", "maranon", "anacardo", "marzipan", "mazapan",
                     "nutella", "praline", "turron", "pesto", "crema de avellana"],
    "mariscos": ["camaron", "camarones", "langosta", "cangrejo", "langostino", "gambas",
                 "marisco", "mariscos", "pulpo", "calamar", "almeja", "ostra", "lambi",
                 "surimi"],
    "pescado": ["pescado", "bacalao", "atun", "salmon", "tilapia", "mero", "chillo",
                "dorado", "sardina", "merluza", "carite", "anchoa", "anchoas",
                "salsa de pescado", "surimi", "caviar", "salsa inglesa", "worcestershire"],
    "lacteos": ["leche", "queso", "yogurt", "mantequilla", "crema", "lacteo", "ricotta",
                "mozzarella", "parmesano", "cottage", "whey", "suero de leche", "caseina",
                "caseinato", "proteina de suero", "proteina de leche", "helado", "mantecado",
                "dulce de leche", "queso crema", "requeson", "kefir", "natilla", "flan",
                "leche condensada", "leche evaporada", "nata", "ghee"],
    "lactosa": ["leche", "queso", "yogurt", "mantequilla", "crema", "ricotta", "mozzarella",
                "whey", "suero de leche", "helado", "mantecado", "dulce de leche", "queso crema",
                "requeson", "kefir", "natilla", "flan", "leche condensada", "leche evaporada"],
    "gluten": ["trigo", "pan", "pasta", "harina de trigo", "galleta", "galletas", "cebada",
               "centeno", "gluten", "tortilla integral", "pan integral", "cuscus", "couscous",
               "seitan", "bulgur", "malta", "cerveza", "semola", "espagueti", "macarrones",
               "lasana", "lasagna", "empanada", "bizcocho", "wheat"],
    "huevo": ["huevo", "huevos", "clara", "claras", "yema", "yemas", "mayonesa", "merengue",
              "aioli", "alioli", "holandesa", "ponche", "mousse"],
    "huevos": ["huevo", "huevos", "clara", "claras", "yema", "yemas", "mayonesa", "merengue",
               "aioli", "alioli", "holandesa", "ponche", "mousse"],
    "soya": ["soya", "soja", "tofu", "salsa de soya", "edamame", "miso", "tempeh",
             "salsa teriyaki", "teriyaki", "natto", "lecitina de soya", "proteina de soya",
             "proteina vegetal texturizada", "tvp"],
}


def _scan_allergen_violations(plan: dict, allergies) -> list:
    """[C2-ALLERGEN-GUARD · 2026-06-13] Backstop DETERMINISTA de seguridad de alérgenos
    (encima del revisor LLM, que puede fallar). Escanea cada ingrediente del plan contra
    las alergias declaradas + sinónimos comunes DD; retorna lista de violaciones
    (meal_name, ingrediente, término_alérgeno). Para alimentos sin sinónimo conocido,
    matchea el texto literal de la alergia. Sesgo a sobre-detectar (seguridad > comodidad).
    Anchor: C2-ALLERGEN-GUARD."""
    try:
        from constants import strip_accents
    except Exception:
        def strip_accents(s):
            import unicodedata
            return "".join(c for c in unicodedata.normalize("NFKD", str(s)) if not unicodedata.combining(c))
    import re as _re
    if isinstance(allergies, str):
        allergies = [allergies]
    forbidden = set()
    for a in (allergies or []):
        a_low = strip_accents(str(a).strip().lower())
        if not a_low or a_low in _MEDICAL_NONE_SENTINELS:
            continue
        matched = False
        for cat, syns in _ALLERGEN_SYNONYMS.items():
            cat_n = strip_accents(cat)
            if a_low == cat_n or cat_n in a_low or a_low in cat_n or \
               any(a_low in strip_accents(s) or strip_accents(s) in a_low for s in syns):
                forbidden.update(strip_accents(s) for s in syns)
                matched = True
        if not matched:
            forbidden.add(a_low)  # alergia free-text → match literal
    if not forbidden:
        return []
    violations = []
    for day in plan.get("days", []):
        for meal in day.get("meals", []):
            for ing in meal.get("ingredients", []):
                ing_low = strip_accents(str(ing).lower())
                for f in forbidden:
                    # `(?:s|es)?` captura el plural español (fresa→fresas, pan→panes,
                    # camaron→camarones) SIN falsos positivos de prefijo (leche≠lechosa).
                    if f and _re.search(r"\b" + _re.escape(f) + r"(?:s|es)?\b", ing_low):
                        violations.append((meal.get("name", "?"), str(ing), f))
                        break
    return violations


# [P1-DIET-HARD-GUARD · 2026-06-15] (gap-audit P1-3) Términos de productos animales por categoría (es-DO,
# se comparan acent-stripped). El scan distingue por dietType: VEGANO prohíbe todo (carne+pescado+huevo+
# lácteo); VEGETARIANO prohíbe carne+pescado (huevo/lácteo OK); PESCETARIANO prohíbe solo carne de tierra.
# Sesgo a sobre-detectar (seguridad de la restricción > comodidad), igual que el allergen guard — un falso
# positivo solo manda el plan al fallback (que es diet-aware vía `_diet_restricted_tokens`).
_DIET_FLESH_TERMS = (  # carne de tierra + aves
    "pollo", "gallina", "pavo", "pavipollo", "res", "ternera", "vacuno", "carne", "carne molida",
    "bistec", "churrasco", "cerdo", "puerco", "chuleta", "chicharron", "tocino", "tocineta", "jamon",
    "salami", "longaniza", "chorizo", "salchicha", "salchichon", "embutido", "costilla", "mondongo",
    "chivo", "cabro", "conejo", "higado", "pernil",
)
_DIET_SEAFOOD_TERMS = (  # pescado + mariscos
    "pescado", "atun", "salmon", "tilapia", "bacalao", "sardina", "mero", "chillo", "dorado",
    "carite", "arenque", "merluza", "camaron", "langosta", "cangrejo", "langostino", "marisco",
    "calamar", "pulpo", "lambi", "surimi", "anchoa", "caviar",
    "mejillones", "mejillon", "almeja", "ostra", "vieira",  # [P1-VARIETY-CATALOG-POOLS] mariscos del catálogo
)
_DIET_EGG_TERMS = (
    "huevo", "huevos", "clara", "claras", "yema", "yemas",
    # [post-review 2026-06-15] procesados con huevo que el sibling allergen guard ('huevo' synonyms) ya
    # cubría. Over-detect bias consistente: una versión vegana ("mayonesa vegana", "merengue de aquafaba")
    # la excusa `_plant_adj` por adyacencia o cae al fallback (vegano-seguro). Nunca se sirve huevo a un vegano.
    "mayonesa", "merengue", "mousse", "alioli", "aioli",
)
_DIET_DAIRY_TERMS = (
    "leche", "queso", "yogur", "yogurt", "mantequilla", "crema", "lacteo", "ricotta", "mozzarella",
    "parmesano", "cottage", "requeson", "kefir", "natilla", "suero de leche", "whey", "caseina",
    "dulce de leche", "leche condensada", "leche evaporada", "nata", "ghee",
    # [post-review 2026-06-15] productos animales procesados que el sibling allergen guard ya cubría
    "helado", "mantecado", "flan",
)


def _canonicalize_diet_type(diet) -> str:
    """[P1-DIET-HARD-GUARD · 2026-06-15] Normaliza dietType a {vegan|vegetarian|pescatarian|balanced},
    cubriendo TODAS las variantes que el backend ACEPTA (`_DIET_TYPE_LEGACY_ACCEPTED` en routers/plans.py:
    EN + ES masculino/femenino — p.ej. 'vegana'/'vegetariana' son data legacy real de health_profile).
    Acent-stripped. SSOT compartido por el scan Y el fallback (cierra el gap post-review donde las formas
    femeninas eludían ambos). Anchor: P1-DIET-HARD-GUARD."""
    try:
        from constants import strip_accents
    except Exception:
        def strip_accents(s):
            import unicodedata
            return "".join(c for c in unicodedata.normalize("NFKD", str(s)) if not unicodedata.combining(c))
    d = strip_accents(str(diet or "").strip().lower())
    if d in ("vegano", "vegan", "vegana"):
        return "vegan"
    if d in ("vegetariano", "vegetarian", "vegetariana", "ovolactovegetariano", "ovo-lacto-vegetariano"):
        return "vegetarian"
    if d in ("pescetariano", "pescatariano", "pescatarian", "pescetarian", "pescetariana", "pescatariana"):
        return "pescatarian"
    return "balanced"


def _scan_diet_violations(plan: dict, diet_type) -> list:
    """[P1-DIET-HARD-GUARD · 2026-06-15] Backstop DETERMINISTA de dietType, espejo de
    `_scan_allergen_violations`. Escanea cada ingrediente contra los productos animales prohibidos por la
    dieta declarada (vegano/vegetariano/pescetariano) y retorna [(meal_name, ingrediente, categoría)].
    Excluye análogos plant-based por ADYACENCIA ("carne de soya", "leche de coco", "salami vegano") — NO
    excusa real-meat con un plant lejano ("pollo con leche de coco" SÍ viola). Sesgo a sobre-detectar.
    Anchor: P1-DIET-HARD-GUARD."""
    try:
        from constants import strip_accents
    except Exception:
        def strip_accents(s):
            import unicodedata
            return "".join(c for c in unicodedata.normalize("NFKD", str(s)) if not unicodedata.combining(c))
    import re as _re
    canon = _canonicalize_diet_type(diet_type)
    if canon == "vegan":
        forbidden = ([(t, "carne") for t in _DIET_FLESH_TERMS]
                     + [(t, "pescado/marisco") for t in _DIET_SEAFOOD_TERMS]
                     + [(t, "huevo") for t in _DIET_EGG_TERMS]
                     + [(t, "lácteo") for t in _DIET_DAIRY_TERMS])
    elif canon == "vegetarian":
        forbidden = ([(t, "carne") for t in _DIET_FLESH_TERMS]
                     + [(t, "pescado/marisco") for t in _DIET_SEAFOOD_TERMS])
    elif canon == "pescatarian":
        forbidden = [(t, "carne de tierra") for t in _DIET_FLESH_TERMS]
    else:
        return []  # balanced / omnívora / desconocida → sin restricción de dieta
    # Análogo plant-based ADYACENTE al término ("de soya", "vegano", "vegetal", "de coco"…). Solo excusa
    # cuando aparece pegado tras el término — un plant lejano no excusa la proteína animal real.
    # [P1-DIET-PLANT-MILK-WIRE · 2026-06-26] +avena/arroz/nuez/nueces/avellana: las leches vegetales nuevas
    # del catálogo (Leche de avena, etc.) NO deben marcarse como lácteo en vegano. Seguro: no existe un
    # producto ANIMAL "leche/yogur de avena/arroz/nuez". tooltip-anchor: P1-DIET-PLANT-MILK-WIRE.
    _plant_adj = _re.compile(
        r"^\s*(?:de\s+|estilo\s+|tipo\s+|a\s+la\s+)?"
        r"(?:soya|soja|coco|almendra|almendras|avena|arroz|nuez|nueces|avellana|mani|cacahuate|maranon|"
        r"anacardo|cajuil|guisante|arveja|seitan|tempeh|vegan[oa]?|vegetal(?:es)?|plant)\b"
    )
    violations = []
    for day in plan.get("days", []) or []:
        for meal in day.get("meals", []) or []:
            for ing in meal.get("ingredients", []) or []:
                ing_low = strip_accents(str(ing).lower())
                for term, label in forbidden:
                    m = _re.search(r"\b" + _re.escape(term) + r"(?:s|es)?\b", ing_low)
                    if not m:
                        continue
                    if _plant_adj.match(ing_low[m.end(): m.end() + 18]):
                        continue  # "carne de soya" / "leche de coco" / "salami vegano" → no viola
                    violations.append((meal.get("name", "?"), str(ing), label))
                    break
    return violations


# [P0-UPDATE-CLINICAL-GUARD · 2026-06-23] Knob del backstop clínico determinista para las
# superficies de UPDATE de platos (swap individual S3, regenerate-day S2, chat modify). Default
# ON: es una capa de SEGURIDAD (alérgenos IgE + dieta hard veg*) que el grafo S1 SÍ corre en
# `review_plan_node` pero que las superficies de edición esquivaban por completo. No-op cuando
# `allergies` está vacío y la dieta es balanced/omnívora → seguro para tests existentes. Rollback
# sin redeploy: MEALFIT_UPDATE_CLINICAL_GUARD=false. tooltip-anchor: P0-UPDATE-CLINICAL-GUARD
UPDATE_CLINICAL_GUARD = _env_bool("MEALFIT_UPDATE_CLINICAL_GUARD", True)

# [P2-UPDATE-CONDITION-SUBST · 2026-06-26] (audit 3-flujos P2) Knob del backstop de SUSTITUCIÓN por
# condición médica en las superficies de UPDATE (swap/regenerate-day/chat-modify). Dedicado (no reusa
# DM2_SUGAR_GUARD) para permitir rollback de SOLO los updates sin tocar el Guard 3 de S1 — ya validado y
# vivo en prod. Default ON. tooltip-anchor: P2-UPDATE-CONDITION-SUBST
UPDATE_CONDITION_SUBST_ENABLED = _env_bool("MEALFIT_UPDATE_CONDITION_SUBST", True)

# [P1-MERCURY-UPDATE-GUARD · 2026-06-24] (re-audit P1-2) Sub-knob del backstop de mercurio-embarazo en
# las superficies de UPDATE. El pescado ALTO en mercurio (metilmercurio = teratógeno) NO es alérgeno IgE
# ni producto veg*-prohibido → los scanners de alérgeno/dieta del backstop NO lo cazan. S1 lo SUSTITUYE
# determinista (Guard 3, `_PREGNANCY_MERCURY_SUBS` en condition_rules) pero swap/regenerate-day/chat-modify
# no pasan por el grafo → la única defensa era la directiva-prompt (falible). Default ON (seguridad).
# Rollback granular sin tocar el knob clínico general: MEALFIT_UPDATE_MERCURY_GUARD=false.
MERCURY_UPDATE_GUARD = _env_bool("MEALFIT_UPDATE_MERCURY_GUARD", True)

# [P0-EXPAND-CONDITION-GUARD · 2026-07-01] (audit objetivo v2 · P0-1) Knob del scan ABORTIVO de términos
# contraindicados por CONDICIÓN médica (DM2/HTA/dislipidemia/embarazo-mercurio) sobre pasos de receta
# generados por LLM FUERA del grafo (/recipe/expand). El backstop sustitutivo
# (`condition_substitution_backstop_for_meal`) opera sobre `ingredients[]` — NO cubre prosa de pasos;
# este detector cierra ese hueco. Default ON (clínico). Rollback sin redeploy.
EXPAND_CONDITION_GUARD = _env_bool("MEALFIT_EXPAND_CONDITION_GUARD", True)
# [P2-HTA-SALT-NORMALIZE · 2026-07-02] (test clínico gemini, batch P2-ENGINE-CLINICAL-SAVERS) Nota
# determinista "bajo en sodio/enjuaga enlatados" en comidas con enlatados/quesos para HTA/ERC — la 2ª
# razón de rechazo del revisor es satisfacible con nota (macro-preservante, patrón food-safety).
HTA_LOWSODIUM_NOTE_ENABLED = _env_bool("MEALFIT_HTA_LOWSODIUM_NOTE", True)

# tokens de riesgo de sodio "oculto" (enlatados/salados/quesos) — accent-free lowercase, estrechos.
_LOWSODIUM_NOTE_TOKENS = ("atun", "sardina", "en lata", "enlatad", "habichuelas cocidas",
                          "garbanzos cocidos", "lentejas cocidas", "queso blanco", "queso fresco",
                          "queso de hoja", "aceitunas", "alcaparras")
_LOWSODIUM_NOTE_SENTINEL = "bajas en sodio y enjuaga"
_LOWSODIUM_NOTE = ("⚠️ Sodio (hipertensión/riñón): elige versiones bajas en sodio y enjuaga los "
                   "enlatados (atún, granos) antes de usarlos; el queso, mejor fresco y bajo en sal.")


def _apply_low_sodium_canned_notes(plan: dict, form_data: dict) -> int:
    """[P2-HTA-SALT-NORMALIZE · 2026-07-02] Nota determinista de bajo-sodio en comidas con
    enlatados/quesos cuando el perfil declara HTA o ERC. Cierra la 2ª razón del rechazo real del
    revisor (test gemini 2026-07-02): "atún en agua/habichuelas/garbanzos/queso sin especificar bajo
    en sodio o enjuague". Macro-preservante (solo añade una nota a recipe[], patrón food-safety),
    idempotente por sentinel, 1 nota máx por comida. Fail-safe → 0. Muta plan.
    tooltip-anchor: P2-HTA-SALT-NORMALIZE"""
    if not HTA_LOWSODIUM_NOTE_ENABLED or not isinstance(plan, dict):
        return 0
    try:
        from condition_rules import detect_active_rules
        _ids = {r.id for r in detect_active_rules(form_data or {})}
        if not (_ids & {"hta", "renal"}):
            return 0
        from constants import strip_accents as _sa_ls
        fixed = 0
        for _d in plan.get("days", []) or []:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                rec = meal.get("recipe")
                if not isinstance(rec, list):
                    rec = [] if rec is None else [str(rec)]
                if any(_LOWSODIUM_NOTE_SENTINEL in str(s) for s in rec):
                    continue  # idempotente
                _hay = _sa_ls(" ".join(str(i) for i in (meal.get("ingredients") or [])).lower())
                if any(t in _hay for t in _LOWSODIUM_NOTE_TOKENS):
                    meal["recipe"] = rec + [_LOWSODIUM_NOTE]
                    meal["_lowsodium_note"] = True
                    fixed += 1
        return fixed
    except Exception as _ls_e:
        logger.warning(f"[P2-HTA-SALT-NORMALIZE] nota falló (no bloquea): {type(_ls_e).__name__}: {_ls_e}")
        return 0


def _scan_mercury_pregnancy_violations(meal: dict, form_data) -> list:
    """[P1-MERCURY-UPDATE-GUARD · 2026-06-24] Detecta pescado ALTO en mercurio en un meal cuando el perfil
    declara embarazo/lactancia (metilmercurio = teratógeno). Reusa los MISMOS términos que el swap
    determinista de S1 (`_PREGNANCY_MERCURY_SUBS` en condition_rules) → SSOT, no se duplica la lista.
    Detección ABORTIVA: devuelve strings de violación (vacío = seguro) para que el backstop fuerce retry
    (swap) o aborte fail-secure (chat-modify), espejo del manejo de alérgenos. EXCLUYE atún a propósito
    (FDA Best/Good Choice en moderación durante el embarazo). Best-effort: cualquier error → [] (no
    bloquea por un fallo del scanner; la directiva-prompt sigue como defensa). tooltip-anchor: P1-MERCURY-UPDATE-GUARD"""
    if not MERCURY_UPDATE_GUARD or not isinstance(meal, dict):
        return []
    try:
        from nutrition_calculator import _is_pregnancy_or_lactation
        if not _is_pregnancy_or_lactation(form_data):
            return []
        from condition_rules import _PREGNANCY_MERCURY_SUBS, _PREGNANCY_MERCURY_NEGATIVES
        from constants import strip_accents
        _terms = _PREGNANCY_MERCURY_SUBS[0][0]
        _negs = tuple(strip_accents(str(_n).lower()) for _n in _PREGNANCY_MERCURY_NEGATIVES)
        _hay = [str(_i) for _i in (meal.get("ingredients") or [])]
        if meal.get("name"):
            _hay.append(str(meal.get("name")))
        out = []
        for _item in _hay:
            _il = strip_accents(_item.lower())
            if any(_n and _n in _il for _n in _negs):
                continue
            for _t in _terms:
                _tl = strip_accents(str(_t).lower())
                if _tl and _tl in _il:
                    out.append(f"pescado alto en mercurio, no apto en embarazo/lactancia: '{_item}'")
                    break
        return out
    except Exception:
        return []


def clinical_backstop_for_meal(meal: dict, *, allergies=None, diet_type=None, form_data=None) -> list:
    """[P0-UPDATE-CLINICAL-GUARD · 2026-06-23] Backstop DETERMINISTA per-comida, reusable por las
    superficies de UPDATE (swap individual S3, regenerate-day S2, chat modify del coach). Espejo
    quirúrgico de los escáneres que el grafo de generación (S1) corre en `review_plan_node`.

    PROBLEMA QUE CIERRA: swap/regenerate-day/modify re-arman el plato 100% con el LLM y NO pasan
    por el grafo → ni reviewer médico ni `_apply_deterministic_clinical_layer` ni los scans de
    alérgeno/dieta. Sin este backstop un alérgico que pide "cámbiale el pollo por camarones"
    obtenía camarones persistidos, o un swap reintroducía cerdo/res en un plan vegano. Las
    `allergies`/`diet_type` deben venir enriquecidas SERVER-SIDE desde `health_profile` por el
    caller (router), NUNCA confiando solo en el body del cliente (espejo de I2 / P0-AGENT-1).

    Envuelve el meal en un mini-plan {days:[{meals:[meal]}]} y reusa `_scan_allergen_violations`
    (C2-ALLERGEN-GUARD, sinónimos DD + over-detect bias) + `_scan_diet_violations`
    (P1-DIET-HARD-GUARD, gateado por DIET_HARD_GUARD, excluye análogos plant-based por adyacencia).

    Devuelve lista de strings legibles de violación (vacía = seguro). FAIL-SECURE: cualquier error
    del escáner devuelve una violación sintética (conservador → no persistir), idéntico criterio
    que `_surgical_promote_blocked_reason`. tooltip-anchor: P0-UPDATE-CLINICAL-GUARD"""
    if not isinstance(meal, dict):
        return []
    out = []
    try:
        mini = {"days": [{"meals": [meal]}]}
        for _mn, _ing, _term in _scan_allergen_violations(mini, allergies or []):
            out.append(f"alérgeno '{_term}' en el ingrediente '{_ing}'")
        if DIET_HARD_GUARD:
            for _mn, _ing, _cat in _scan_diet_violations(mini, diet_type):
                out.append(f"{_cat} (no apto para la dieta declarada): '{_ing}'")
        # [P1-MERCURY-UPDATE-GUARD · 2026-06-24] (re-audit P1-2) Mercurio-embarazo: no es alérgeno IgE ni
        # producto veg* → los scanners de arriba no lo cazan. Solo corre si `form_data` declara embarazo/
        # lactancia (el helper es no-op si no). Cierra el hueco de paridad con el swap determinista de S1.
        if form_data is not None:
            out.extend(_scan_mercury_pregnancy_violations(meal, form_data))
    except Exception as _clin_e:
        return [f"error de re-validación clínica ({type(_clin_e).__name__}: {_clin_e}) — bloqueo conservador"]
    return out


def slot_coherence_backstop_for_meal(meal: dict, meal_type: str) -> list:
    """[P1-SLOT-APPROPRIATENESS · 2026-06-27] (audit G4) Backstop DETERMINISTA per-comida de coherencia
    de HORARIO, reusable por las superficies de UPDATE (swap S3 / regenerate-day S2). Espejo de
    `clinical_backstop_for_meal` pero CALIDAD, no seguridad: reusa el SSOT
    `constants.slot_violations_for_meal_name` (match word-boundary sobre el NOMBRE). Devuelve lista de
    strings de violación (vacía = ok). Gateado por SLOT_APPROPRIATENESS_GATE_ENABLED. FAIL-OPEN: un error
    del detector NUNCA bloquea el update (a diferencia del backstop clínico, abortivo) — la coherencia de
    horario es cosmética; degradarla es preferible a un cero-plato. tooltip-anchor: P1-SLOT-APPROPRIATENESS"""
    if not SLOT_APPROPRIATENESS_GATE_ENABLED or not isinstance(meal, dict):
        return []
    try:
        slot_key = canonical_slot_key(meal_type) or _SLOT_KEY_MAP.get(_norm_text(meal_type))
        if not slot_key:
            return []
        out = []
        for v in slot_violations_for_meal_name(meal.get("name", ""), slot_key):
            out.append(f"{v['label']} no corresponde al {slot_key} (coherencia de horario es-DO)")
        # [P2-SLOT-INGREDIENT-RICE · 2026-07-01] (audit v2 slots GAP-1) paridad updates: el mismo pase
        # ingredient-level del productor S1 (arroz oculto en ingredients de un DESAYUNO con nombre inocuo).
        try:
            from constants import slot_ingredient_violations as _siv_b
            for v in _siv_b(meal.get("ingredients") or [], slot_key):
                out.append(f"{v['label']} (coherencia de horario es-DO)")
        except Exception:
            pass
        return out
    except Exception:
        return []


def renal_protein_trim_for_update(meals: list, protein_ceiling_g: float, db=None, *, renal_capped: bool = True) -> bool:
    """[P1-RENAL-UPDATE-ENFORCE · 2026-06-24] (re-audit P1-1) Re-enforza el cap renal KDIGO de proteína en
    las superficies de UPDATE (swap S3 / regenerate-day S2 / chat-modify). S1 capea la proteína per-comida/
    día en el grafo (`_enforce_renal_per_meal`, Guard 1, seguridad iatrogénica ~0.8 g/kg en ERC G3-G5) pero
    los updates NO pasan por el grafo → un swap/regen podía entregar proteína POR ENCIMA del techo sin
    ningún guard determinista (el backstop solo cubre alérgeno/dieta).

    Reusa `_trim_day_protein_to_ceiling(ceiling_pct=1.0)`: trima SOLO hacia abajo (jamás sube proteína —
    subirla sería iatrogénico en ERC). `meals` puede ser [1 meal] (techo = target del slot, ya renal-aware
    porque el plan se capeó en S1) o la lista del día (techo = cap del día `renal_protein_cap.protein_g`).
    No-op si no `renal_capped`. Gateado por RENAL_CAP_ENABLED (seguridad iatrogénica, NO por
    UPDATE_CLINICAL_GUARD — mismo desacople que S1). Best-effort: error → log + deja el/los meal(s) intactos
    (el cap ya se aplicó en S1; el gate ±15% acota el drift residual). Devuelve True si trimó.
    tooltip-anchor: P1-RENAL-UPDATE-ENFORCE"""
    if not (RENAL_CAP_ENABLED and renal_capped):
        return False
    if not isinstance(meals, list) or not meals:
        return False
    try:
        _ceil = float(protein_ceiling_g or 0)
    except Exception:
        _ceil = 0.0
    if _ceil <= 0:
        return False
    try:
        if db is None:
            from nutrition_db import IngredientNutritionDB
            db = IngredientNutritionDB()
        _trimmed = _trim_day_protein_to_ceiling(meals, _ceil, db, ceiling_pct=1.0)
        if _trimmed:
            logger.info(
                f"🫘 [P1-RENAL-UPDATE-ENFORCE] proteína de update trimada al techo renal "
                f"(~{round(_ceil)}g) en {len(meals)} plato(s)"
            )
        return _trimmed
    except Exception as _rt_e:
        logger.warning(
            f"[P1-RENAL-UPDATE-ENFORCE] trim renal de update falló (no bloquea): "
            f"{type(_rt_e).__name__}: {_rt_e}"
        )
        return False


def food_safety_backstop_for_meal(meal: dict) -> int:
    """[P2-FOOD-SAFETY-UPDATE · 2026-06-24] (re-audit P2-1) Re-aplica la mitigación determinista de
    seguridad alimentaria (huevo crudo FS1 + pescado/marisco/carne crudos) en las superficies de UPDATE
    (swap S3 / regenerate-day S2 / chat-modify). S1 la corre en `_apply_deterministic_clinical_layer`
    (Guard 2) pero los updates NO pasan por el grafo → un swap a 'ceviche'/'sushi'/'huevo en batido' se
    persistía sin la nota de seguridad. Envuelve el meal en un mini-plan y reusa `_apply_food_safety_fixes`
    (MACRO-PRESERVANTE: solo añade una nota a la receta, salvo blended-egg que sustituye; shopping-safe;
    idempotente). FAIL-OPEN: la nota es advisory; un error del scanner NUNCA bloquea el update (a diferencia
    del backstop clínico de alérgeno/dieta, que es abortivo). Gateado por FOOD_SAFETY_GUARD (el mismo de
    S1). Mutates `meal` in-place (es el mismo objeto dentro del mini-plan). Retorna nº de mitigaciones.
    tooltip-anchor: P2-FOOD-SAFETY-UPDATE"""
    if not FOOD_SAFETY_GUARD or not isinstance(meal, dict):
        return 0
    try:
        return _apply_food_safety_fixes({"days": [{"meals": [meal]}]})
    except Exception as _fs_e:
        logger.warning(f"[P2-FOOD-SAFETY-UPDATE] food-safety backstop falló (no bloquea): {type(_fs_e).__name__}: {_fs_e}")
        return 0


def condition_substitution_backstop_for_meal(meal: dict, form_data: dict) -> int:
    """[P2-UPDATE-CONDITION-SUBST · 2026-06-26] (audit 3-flujos P2) Re-aplica la SUSTITUCIÓN determinista
    de ingredientes por condición médica en las superficies de UPDATE (swap S3 / regenerate-day S2 /
    chat-modify): DM2 → azúcar añadida→stevia/agua; HTA → embutidos/cubitos/bacalao salado→fresco;
    dislipidemia → mantequilla/lácteos enteros/tocino→magro. S1 la corre como Guard 3 del grafo
    (`_apply_condition_substitutions`, el mecanismo de enforcement ELEGIDO en
    clinical_enforcement_decisions.md) pero los updates NO pasan por el grafo → un swap/modify a
    'longaniza'/'mantequilla'/'azúcar' se persistía contraindicado (la única defensa era la
    directiva-prompt advisory, falible con un LLM). Envuelve el meal en un mini-plan y reusa
    `_apply_condition_substitutions` (PRESERVA el prefijo de cantidad comprable, RECOMPUTA macros por
    delta, IDEMPOTENTE, mutates `meal` in-place — es el mismo objeto dentro del mini-plan). FAIL-OPEN:
    la sustitución es advisory (NUNCA bloquea el update, a diferencia del backstop de alérgeno/dieta que
    es abortivo). Gateado por UPDATE_CONDITION_SUBST_ENABLED (rollback independiente de S1) + DM2_SUGAR_GUARD
    (mismo feature-gate de S1); el propio `_apply_condition_substitutions` respeta CONDITION_RULES_ENABLED.
    Requiere `form_data['medicalConditions']` (enriquecido server-side por `_enrich_clinical_from_profile`
    en swap/regenerate-day; desde el health_profile en chat-modify). Espejo de food_safety_backstop_for_meal.
    Retorna nº de comidas afectadas. tooltip-anchor: P2-UPDATE-CONDITION-SUBST"""
    if not UPDATE_CONDITION_SUBST_ENABLED or not DM2_SUGAR_GUARD or not isinstance(meal, dict):
        return 0
    try:
        _n_cs = _apply_condition_substitutions({"days": [{"meals": [meal]}]}, form_data or {})
        # [P2-HTA-SALT-NORMALIZE · 2026-07-02] paridad updates: la nota de bajo-sodio/enjuague para
        # enlatados/quesos también corre en swap/regen-day/chat-modify (mismo mini-plan wrap).
        try:
            _n_cs += _apply_low_sodium_canned_notes({"days": [{"meals": [meal]}]}, form_data or {})
        except Exception:
            pass
        return _n_cs
    except Exception as _cs_e:
        logger.warning(f"[P2-UPDATE-CONDITION-SUBST] condition-subst backstop falló (no bloquea): {type(_cs_e).__name__}: {_cs_e}")
        return 0


def condition_prohibited_violations_for_meal(meal: dict, form_data: dict) -> list:
    """[P0-EXPAND-CONDITION-GUARD · 2026-07-01] (audit objetivo v2 · P0-1) Detección ABORTIVA de términos
    contraindicados por CONDICIÓN médica (DM2 miel/azúcar/refinados-IG, HTA cubitos/embutidos/sazones,
    dislipidemia mantequilla/lácteos enteros, embarazo pescado alto en mercurio) en los items de
    `meal['ingredients']`. Reusa el SSOT `condition_rules.collect_substitutions` — los MISMOS
    tokens+negatives que el Guard 3 de S1 (`_apply_condition_substitutions`) y que
    `condition_substitution_backstop_for_meal` — pero DETECTA en vez de sustituir: pensado para
    superficies donde el contenido ofensor vive en PROSA de pasos (p.ej. /recipe/expand, que pasa los
    pasos del Chef como `ingredients`). Reescribir prosa es frágil; rechazar es barato (soft-fail 200 +
    retry, patrón del scan de alérgenos de expand).

    Diferencias DELIBERADAS vs el backstop sustitutivo:
    (a) NO escanea `name`: en expand el nombre es PRE-existente y ya validado por S1 — incluirlo
        bloquearía el retry para siempre (el nombre no cambia entre reintentos del Chef).
    (b) SALTA pasos-nota deterministas (⚠/💡/⚕): la nota clínica "se sustituyó miel → Stevia" contiene
        el token ofensor POR DISEÑO y no es instrucción de cocción.
    Best-effort (espejo P1-MERCURY-UPDATE-GUARD): cualquier error → [] — la sustitución de S1 + la
    directiva-prompt siguen como defensa; el fail-secure abortivo queda para alérgenos IgE
    (`clinical_backstop_for_meal`). Devuelve strings legibles de violación (vacío = seguro).
    tooltip-anchor: P0-EXPAND-CONDITION-GUARD"""
    if not EXPAND_CONDITION_GUARD or not CONDITION_RULES_ENABLED or not isinstance(meal, dict):
        return []
    try:
        from condition_rules import collect_substitutions
        from constants import strip_accents
        subs = collect_substitutions(form_data or {})
        if not subs:
            return []
        out = []
        for _item in (meal.get("ingredients") or []):
            _s = str(_item)
            if _is_recipe_safety_note_step(_s) or "⚕" in _s:
                continue
            _il = strip_accents(_s.lower())
            for s in subs:
                if any(_n and _n in _il for _n in (s.get("negatives") or ())):
                    continue
                if any(_t and strip_accents(str(_t).lower()) in _il for _t in (s.get("tokens") or ())):
                    out.append(
                        f"{s.get('label')} (contraindicado por condición '{s.get('condition')}'): '{_s[:120]}'"
                    )
                    break
        return out
    except Exception as _cpv_e:
        logger.warning(f"[P0-EXPAND-CONDITION-GUARD] scan de condición no-op (no bloquea): "
                       f"{type(_cpv_e).__name__}: {_cpv_e}")
        return []


def recompute_micronutrient_report_for_plan(plan: dict, form_data: dict, db=None) -> bool:
    """[P1-UPDATE-MICROS · 2026-06-23] (audit inteligencia P1-7) Recomputa
    `plan['micronutrient_report']` (+ `micronutrient_supplement_advice`) tras un update de platos
    (swap individual / regenerate-day) para que el panel de micros y el PDF NO queden stale — el
    frontend (Dashboard / NotificationCenter) los lee. Espejo del Guard 5 de `assemble_plan_node`.

    Best-effort: cualquier error deja el plan intacto (el panel es advisory, nunca bloquea el
    update). Devuelve True si recomputó. tooltip-anchor: P1-UPDATE-MICROS"""
    if not MICRONUTRIENT_REPORT_ENABLED or not isinstance(plan, dict):
        return False
    try:
        from micronutrients import build_micronutrient_report
        if db is None:
            from nutrition_db import IngredientNutritionDB
            db = IngredientNutritionDB()
        _fd = form_data or {}
        _sex = _fd.get("gender") or "female"
        try:
            from nutrition_calculator import _is_pregnancy_or_lactation as _ipl
            _pregnant = bool(_ipl(_fd))
        except Exception:
            _pregnant = False
        _k_elev = False
        try:
            from medication_rules import detect_potassium_elevating_med
            _k_elev = bool(detect_potassium_elevating_med(_fd))
        except Exception:
            _k_elev = False
        _ndays = len(plan.get("days") or []) or 1
        try:
            _daily_kcal = sum(
                _meal_macro_num(_m.get("cals"))
                for _d in (plan.get("days") or [])
                for _m in ((_d.get("meals") or []) if isinstance(_d, dict) else [])
            ) / _ndays
        except Exception:
            _daily_kcal = 0.0
        _mn = build_micronutrient_report(
            plan, db, sex=_sex,
            conditions=_condition_strings(_fd), daily_kcal=_daily_kcal,
            fiber_per_1000kcal=DM2_FIBER_G_PER_1000KCAL,
            age=_fd.get("age"), pregnant=_pregnant, k_elevating_med=_k_elev,
        )
        plan["micronutrient_report"] = _mn
        # [P2-DELIVERED-MACROS · 2026-07-01] este hook corre en las 3 superficies de update → los campos
        # "entregado real" no quedan stale tras swap/chat-modify/regen-day.
        refresh_delivered_macros(plan)
        if SUPPLEMENT_ADVICE_ENABLED:
            try:
                from micronutrients import build_supplement_recommendations
                _supp = build_supplement_recommendations(
                    _mn, sex=_sex, age=_fd.get("age"), pregnant=_pregnant,
                    conditions=_condition_strings(_fd))  # [P1-SUPPLEMENT-CONDITION-AWARE] suprime Mg en ERC
                if _supp.get("count"):
                    plan["micronutrient_supplement_advice"] = _supp
            except Exception:
                pass
        logger.info(
            f"🧪 [P1-UPDATE-MICROS] panel de micros recomputado post-update "
            f"(cobertura {int(_mn.get('coverage', 0) * 100)}%, {len(_mn.get('gaps', []))} gap(s))"
        )
        return True
    except Exception as _mn_e:
        logger.warning(f"[P1-UPDATE-MICROS] recompute micro report falló (no bloquea): {type(_mn_e).__name__}: {_mn_e}")
        return False


def _close_micro_gaps_for_plan(plan: dict, form_data: dict, db=None, pantry_strict: bool = False) -> int:
    """[P1-MICRONUTRIENT-CLOSER · 2026-06-29 · cobertura+updates re-audit P1-MICRO-CLOSER-COVERAGE/UPDATES 2026-06-29]
    Lever DETERMINISTA de micros alcanzables —
    espejo del closer de proteína (`_close_protein_gap_for_meal`/`_repair_protein_floor_post_caps`), que cierra
    la asimetría identificada en el audit: la proteína tiene cierre determinista post-caps, pero los micros eran
    SOLO un nudge al prompt (advisory). Para un usuario sano con fibra 18/25g nada cerraba la brecha.

    Corre tras el macro engine. Detecta los micros ALCANZABLES (`_MICRO_CLOSER_KEYS` = fibra/Mg/Ca + hierro/folato/
    zinc/vit C tras P1-MICRO-CLOSER-COVERAGE) que el reporte advisory marca genuinamente BAJO el piso DRI **con
    cobertura alta** (`status=='bajo'`, NO 'estimado_bajo' que es incierto). Recorre DÍA-por-fuera, micro-por-dentro,
    con un PRESUPUESTO de kcal COMPARTIDO por día (`MICRONUTRIENT_CLOSER_MAX_KCAL_PER_DAY`) → el total añadido al día
    está acotado sin importar cuántos micros se cierren (cierra el invariante "≤80 kcal/día" que un budget per-micro
    rompía al crecer el set de micros). Para cada micro deficitario ESCALA el ingrediente existente más rico
    (vegetal/leguminosa/hoja/lácteo/carne, ya en el plato), acotado por:
      - factor ≤ MICRONUTRIENT_CLOSER_MAX_SCALE,
      - kcal añadidas del día ≤ presupuesto restante (compartido entre micros),
      - el total del micro tras escalar ≤ su TECHO UL (`_MICRO_CLOSER_UL`, p.ej. hierro 45mg) — defensa contra
        toxicidad al escalar hígado/vísceras (fibra/Mg/Ca no llevan UL de comida),
    y recomputa los macros del plato desde strings. NO añade ingredientes nuevos → NO toca alérgenos, ni la
    coherencia receta↔lista, ni introduce platos raros (el ingrediente ya estaba en la receta y la lista).

    SKIPS clínicos: en ERC (renal) NO cierra fibra/Mg/hierro/folato/zinc/vit C (leguminosas/hígado/cítricos cargan
    K/P/proteína contraindicados — la adecuación de micros en ERC la maneja el panel renal-aware + el gate de
    nefrólogo); solo calcio queda cerrable (comportamiento previo). `pantry_strict=True` → SKIP total: escalar un
    ingrediente añade comida, contraindicado al cocinar ESTRICTAMENTE desde la nevera (la superficie pantry-strict
    no puede "comprar más" — el closer es una inteligencia de "ir de compras"). ON por default
    (`MICRONUTRIENT_CLOSER_ENABLED`, nació OFF; flip P1-OBJECTIVE-LEVERS-ON 2026-06-29 — mismo rollout
    que los closers de swap y el soft-reject). Idempotente en la práctica (tras cerrar, el día ya cumple → no
    re-escala), fail-open. Muta `plan` in-place. Devuelve nº de ajustes. tooltip-anchor: P1-MICRONUTRIENT-CLOSER"""
    if not MICRONUTRIENT_CLOSER_ENABLED or pantry_strict or not isinstance(plan, dict):
        return 0
    try:
        from micronutrients import build_micronutrient_report
        from nutrition_db import rescale_ingredient_string as _resc
        _fd = form_data or {}
        # [P1-CLOSER-BARIATRIC-GUARD · 2026-07-05] bariátrico → skip TOTAL (seed + escala), ANTES
        # de instanciar el catálogo. El closer añade volumen/gramos que los caps bariátricos de la
        # capa clínica ya no re-validan (el re-fire P2-2 corre después de ella); los micros post-op
        # van por protocolo de suplementación, no por "comer más". Ver knob para el detalle.
        if MICRO_CLOSER_BARIATRIC_SKIP and _is_bariatric_condition(_fd):
            logger.info("🧪 [P1-CLOSER-BARIATRIC-GUARD] perfil bariátrico → micro-closer/seeder "
                        "omitido (volumen/textura post-op; micros por protocolo de suplementación)")
            return 0
        if db is None:
            from nutrition_db import IngredientNutritionDB
            db = IngredientNutritionDB()
        _sex = _fd.get("gender") or "female"
        try:
            from nutrition_calculator import _is_pregnancy_or_lactation as _ipl
            _pregnant = bool(_ipl(_fd))
        except Exception:
            _pregnant = False
        _k_elev = False
        try:
            from medication_rules import detect_potassium_elevating_med
            _k_elev = bool(detect_potassium_elevating_med(_fd))
        except Exception:
            _k_elev = False
        # [P2-VITK-LEVER · 2026-07-02] anticoagulante declarado → vit K jamás se cierra (consistencia INR).
        # Fail-secure: si la detección falla, asumimos anticoagulante (no escalar vit K sobre duda clínica).
        _anticoag = True
        try:
            from medication_rules import detect_anticoagulant
            _anticoag = bool(detect_anticoagulant(_fd))
        except Exception:
            _anticoag = True
        _conditions = _condition_strings(_fd)
        _renal = any(("renal" in str(c).lower() or "erc" in str(c).lower()) for c in (_conditions or []))
        _days = plan.get("days") or []
        _ndays = len(_days) or 1
        try:
            _daily_kcal = sum(
                _meal_macro_num(_m.get("cals"))
                for _d in _days
                for _m in ((_d.get("meals") or []) if isinstance(_d, dict) else [])
            ) / _ndays
        except Exception:
            _daily_kcal = 0.0
        _report = build_micronutrient_report(
            plan, db, sex=_sex, conditions=_conditions, daily_kcal=_daily_kcal,
            fiber_per_1000kcal=DM2_FIBER_G_PER_1000KCAL,
            age=_fd.get("age"), pregnant=_pregnant, k_elevating_med=_k_elev,
        )
        floors = {}
        _estimado_bajo_skipped = 0
        for g in (_report.get("gaps") or []):
            k = g.get("key")
            if k not in _MICRO_CLOSER_KEYS:
                continue
            if g.get("status") != "bajo":  # 'estimado_bajo' = cobertura incierta → no forzar
                # [P2-MICRO-ESTIMADO-BAJO · 2026-06-29] (re-audit objetivo · P2) Telemetría: un micro cerrable
                # bajo el piso pero con cobertura INCIERTA (status='estimado_bajo' por NULLs residuales en el
                # catálogo) se omite a propósito (no forzar sobre datos inciertos — conservador-by-design). Lo
                # contamos para vigilar si el lever real (backfill de NULLs en el catálogo) sigue pendiente.
                # tooltip-anchor: P2-MICRO-ESTIMADO-BAJO
                if g.get("status") == "estimado_bajo":
                    _estimado_bajo_skipped += 1
                continue
            # [P1-MICRO-CLOSER-COVERAGE · 2026-06-29] En ERC, además de Mg/fibra, NO cerramos hierro/folato/zinc/
            # vit C: sus fuentes (legumbres/hígado/cítricos) cargan K/P/proteína contraindicados. Solo calcio queda
            # cerrable (preserva comportamiento previo). La adecuación de micros en renal la maneja el panel
            # renal-aware + el gate de nefrólogo, no este lever de "ir de compras".
            # [P2-MICRO-CLOSER-KEYS-EXT · 2026-07-01] las keys nuevas también quedan fuera en ERC (K contraindicado;
            # vit E/omega-3 vía nueces/semillas cargan K/P).
            # [P2-MICRO-CLOSER-VITA-SE · 2026-07-01] vit A se ACUMULA en ERC (excreción renal reducida →
            # hipervitaminosis A es hallazgo común en CKD; KDOQI desaconseja suplementarla) y selenio sigue
            # el patrón "solo calcio cerrable en renal" del resto de keys.
            if _renal and k in _MICRO_CLOSER_RENAL_EXCLUDED:
                continue
            # [P2-MICRO-CLOSER-KEYS-EXT · 2026-07-01] potasio NUNCA se cierra bajo medicamento K-elevador
            # (espironolactona/IECA free-text incluidos vía P1-MICRO-CLINICAL-FREETEXT) — hiperkalemia iatrogénica.
            if k == "potassium_mg" and _k_elev:
                continue
            # [P2-VITK-LEVER · 2026-07-02] vit K jamás bajo anticoagulante (consistencia INR > cerrar el piso).
            if k == "vit_k_mcg" and _anticoag:
                continue
            try:
                floors[k] = float(g.get("piso") or 0)
            except Exception:
                continue
        if _estimado_bajo_skipped:
            logger.info(f"🧪 [P2-MICRO-ESTIMADO-BAJO] {_estimado_bajo_skipped} micro(s) cerrable(s) omitido(s) por "
                        f"status=estimado_bajo (cobertura incierta; lever real: backfill de NULLs en el catálogo)")
        # [P2-AUDIT-V5-BATCH · 2026-07-02] (GAP-M2) Targeting per-día (follow-up declarado por
        # P1-MICRO-PERDAY-FLOOR): los micros "low" del worst-day flaggeado (<60% del piso en ≥2
        # micros — umbrales del detector INTACTOS) entran al set de floors aunque el PROMEDIO del
        # plan cumpla. El loop per-día de abajo solo escala los DÍAS deficientes (día con
        # day_total >= floor hace `continue`) → los días OK no se tocan. Mismas exclusiones
        # clínicas del loop de arriba. Knob OFF por rollout (medir→actuar con la serie del banner).
        if MICRO_CLOSER_PERDAY_ENABLED:
            try:
                _pdf_cl = _report.get("per_day_floors") if isinstance(_report, dict) else None
                if isinstance(_pdf_cl, dict) and _pdf_cl.get("flagged"):
                    _pd_low_cl = ((_pdf_cl.get("worst_day") or {}).get("low")) or []
                    _panel_by_key = {p.get("key"): p for p in (_report.get("panel") or []) if isinstance(p, dict)}
                    for k in _pd_low_cl:
                        if k in floors or k not in _MICRO_CLOSER_KEYS:
                            continue
                        if _renal and k in _MICRO_CLOSER_RENAL_EXCLUDED:
                            continue
                        if k == "potassium_mg" and _k_elev:
                            continue
                        if k == "vit_k_mcg" and _anticoag:
                            continue
                        try:
                            _fv_cl = float((_panel_by_key.get(k) or {}).get("piso") or 0)
                        except (TypeError, ValueError):
                            continue
                        if _fv_cl > 0:
                            floors[k] = _fv_cl
                            logger.info(f"🧪 [P2-AUDIT-V5-BATCH] (GAP-M2) micro '{k}' entra al closer por "
                                        f"worst-day (promedio OK, día deficiente)")
            except Exception as _pdcl_e:
                logger.debug(f"[P2-AUDIT-V5-BATCH] (GAP-M2) targeting per-día no-op: {_pdcl_e}")
        if not floors:
            return 0
        # [P2-MICRO-CLOSER-CEILINGS · 2026-07-01] (audit micros GAP-5) El closer era CIEGO a los techos al
        # escalar: en dislipidemia/HTA el contribuyente más rico en calcio suele ser QUESO → 1.6× añadía
        # satfat/sodio y el propio closer disparaba después el banner condition_panel_gap (degradación
        # auto-infligida); en ERC la rama calcio escalaba lácteo cargando K/P sin check. Guard token-based
        # determinista: bajo esas condiciones se SALTAN los contribuyentes de riesgo (el siguiente contribuyente
        # richest-first toma su lugar; si no hay, el residual se loguea como antes). tooltip-anchor: P2-MICRO-CLOSER-CEILINGS
        _cstr = " ".join(str(c).lower() for c in (_conditions or []))
        _dyslip_or_hta = any(t in _cstr for t in ("dislip", "colesterol", "hiperlip", "hipertens", "hta",
                                                  "presion alta", "presión alta"))
        # [P2-CLOSER-DM2-GI-GUARD · 2026-07-05] (audit solver+seeder P2-4) El closer era DM2-ciego al
        # escalar: cerrar potasio/vit C podía inflar 1.6× la fruta alto-IG de un diabético (guineo
        # maduro/mango/piña = azúcar). Mismo patrón token-based del guard dislip/HTA: bajo DM2 se
        # SALTAN los contribuyentes alto-IG (el siguiente richest-first toma su lugar; sin
        # alternativa, el residual se loguea como siempre). Tokens accent-stripped (el callsite pasa
        # `_ing_low` ya normalizado); "mangu" NO matchea "mango".
        _dm2 = any(t in _cstr for t in ("diabet", "dm2", "glicem", "glucem", "prediabet",
                                        "resistencia a la insulina"))
        # Word-boundary OBLIGATORIO (lección 'res'↔'fresas' de CATALOG-POOLS): "pina" como
        # substring matchea dentro de "es-PINA-ca" y bloquearía justo la alternativa verde.
        # Plural opcional (`s?`): uvas/pasas/mangos.
        _DM2_HIGHGI_TOKENS = ("guineo", "platano maduro", "mango", "pina", "uva",
                              "pasa", "sandia", "melon", "miel")
        _dm2_gi_re = _re.compile(
            r"\b(?:" + "|".join(_re.escape(t) for t in _DM2_HIGHGI_TOKENS) + r")s?\b")
        _CEIL_RISK_TOKENS = ("queso", "tocino", "salami", "embutido", "jamon", "jamón", "mantequilla",
                             "longaniza", "chorizo", "salchich", "manteca")
        _DAIRY_TOKENS = ("queso", "leche", "yogur", "lacteo", "lácteo", "ricotta", "cottage", "requeson", "requesón")
        # [Sd-P2-d · 2026-07-07] Almidones/harinas refinadas alto-IG — los portadores DOMINANTES de potasio/
        # vit C en un plan dominicano. Word-boundary OBLIGATORIO (lección 'res'↔'fresas'): '\bpapa\b' NO
        # matchea 'papaya'/'papadum'; 's?' cubre plurales (papas/tostones). Los tokens de DOS palabras
        # ('arroz blanco'/'pan blanco') NO matchean 'arroz integral'/'pan integral' (bajo-IG → siguen
        # escalables). Tokens accent-stripped (el callsite ya normaliza _ing_low con strip_accents).
        _DM2_HIGHGI_STARCH_TOKENS = ("papa", "patata", "batata", "yuca", "casabe", "mangu",
                                     "tostones", "platano verde", "pure de papa",
                                     "arroz blanco", "pan blanco")
        _dm2_starch_re = _re.compile(
            r"\b(?:" + "|".join(_re.escape(t) for t in _DM2_HIGHGI_STARCH_TOKENS) + r")s?\b")
        # [Sd-P2-e · 2026-07-07] Portadores de calcio NO-lácteos con alto fósforo/potasio (contraindicados en
        # ERC). 'leche de almendras' (fortificada, renal-safe) YA cae en la rama _DAIRY_TOKENS por 'leche',
        # así que aquí solo capturamos el fruto seco/semilla/pescado-con-espina/hoja entero. Word-boundary +
        # accent-stripped.
        _RENAL_CA_NONDAIRY_TOKENS = ("ajonjoli", "sesamo", "tahini", "almendra", "sardina",
                                     "espinaca", "brocoli", "tofu", "kale", "col rizada")
        _renal_ca_nondairy_re = _re.compile(
            r"\b(?:" + "|".join(_re.escape(t) for t in _RENAL_CA_NONDAIRY_TOKENS) + r")s?\b")

        def _ceiling_risky_contributor(_k_micro: str, _ing_low: str) -> bool:
            if _dyslip_or_hta and any(t in _ing_low for t in _CEIL_RISK_TOKENS):
                return True
            if _renal and _k_micro == "calcium_mg" and any(t in _ing_low for t in _DAIRY_TOKENS):
                return True
            # [Sd-P2-e] renal + calcio: los portadores NO-lácteos alto-P/K también se saltan (el fall-through
            # del skip lácteo aterrizaba justo en estos). Fail-secure a residual honesto sobre carga renal.
            if (_renal and _k_micro == "calcium_mg" and RENAL_CALCIUM_NONDAIRY_GUARD
                    and _renal_ca_nondairy_re.search(_ing_low)):
                return True
            # [P2-CLOSER-DM2-GI-GUARD] fruta/azúcar alto-IG jamás es target de escalado en DM2.
            if _dm2 and _dm2_gi_re.search(_ing_low):
                return True
            # [Sd-P2-d] DM2: almidones/harinas refinadas alto-IG tampoco (papa/yuca/arroz blanco/pan blanco).
            if _dm2 and DM2_HIGHGI_STARCH_GUARD and _dm2_starch_re.search(_ing_low):
                return True
            return False

        adjustments = 0
        # [P1-MICRO-CLOSER-COVERAGE · 2026-06-29] DÍA-por-fuera con presupuesto de kcal COMPARTIDO entre micros →
        # el total añadido por día está acotado a MICRONUTRIENT_CLOSER_MAX_KCAL_PER_DAY sin importar cuántos micros
        # se cierren (con 7 micros un budget per-micro permitía hasta 7× el techo → rompía la banda macro). El aporte
        # por micro se recomputa DESPUÉS de cada escala (re-lee ingredients) → si una hoja cubre fibra+folato+hierro,
        # escalarla una vez baja el déficit de los 3.
        # [P1-CLOSER-SEED-PRIORITY · 2026-07-05] Los micros SEMBRABLES van PRIMERO en la cola del
        # día: el presupuesto kcal (120) es COMPARTIDO entre todos los micros del día y se consume
        # en orden de iteración — que era el orden del PANEL, con vit E/omega-3 al final. Caso vivo
        # plan a5c9983d: Día 1 en 7.2/15 de vit E y 0.41/1.6 de omega-3 (ambos bajo el umbral del
        # banner), la semilla NUNCA entró (cero 🌱 en la corrida) porque los micros tempranos
        # (fibra/calcio/magnesio) agotaron el presupuesto escalando → guard de semilla (>25 kcal)
        # sin fondos → banner micro_worst_day pese a tener el arsenal completo. Las semillas son
        # el cierre más kcal-eficiente (girasol 3.5mg vit E por 58 kcal) — van primero.
        # [P1-MICRO-BUDGET-NONFAT-FIRST · 2026-07-07] los grasa-basados (omega3/vitE) tienen backstop propio
        # (fatswap para escalar + reserva para sembrar) → van al FINAL del budget compartido; hierro/folato
        # (sin backstop, mayor consecuencia) y vitA (seed kcal-eficiente) primero. Rollback knob → orden viejo.
        if MICRO_BUDGET_NONFAT_FIRST:
            _floors_ordered = sorted(floors.items(), key=lambda kv: _micro_budget_rank(kv[0]))
        else:
            _floors_ordered = sorted(floors.items(), key=lambda kv: kv[0] not in _MICRO_SEED_SOURCES)
        for _d in _days:
            if not isinstance(_d, dict):
                continue
            kcal_budget_left = float(MICRONUTRIENT_CLOSER_MAX_KCAL_PER_DAY)
            # [P1-MICRO-BUDGET-NONFAT-FIRST · 2026-07-07] reserva DEDICADA para el seed de micros
            # grasa-basados (día-sin-portador) → ponerlos al final del budget compartido no mata su siembra.
            _fat_seed_reserve = float(MICRO_FAT_SEED_RESERVE_KCAL)
            for k, floor in _floors_ordered:
                if kcal_budget_left <= 1.0 and k not in _FAT_BASED_MICROS:
                    # [P1-MICRO-BUDGET-NONFAT-FIRST · 2026-07-07] budget compartido agotado: los micros
                    # NO-grasa (que solo cierran escalando con el compartido) se saltan; los grasa-basados
                    # (al FINAL del orden nuevo) SIGUEN — tienen backstop propio (fatswap para escalar el
                    # portador con su budget, reserva para sembrar si no hay portador). Antes era un `break`
                    # universal → ponerlos al final los habría dejado SIN cierre alguno.
                    continue
                ing_key = _MICRO_CLOSER_INGREDIENT_KEY[k]
                _ul = _MICRO_CLOSER_UL.get(k)
                # [P2-MICRO-MULTISOURCE · 2026-06-29] (re-audit objetivo · P2 MICRO-CLOSER-SINGLE-INGREDIENT)
                # Recolecta TODOS los contribuyentes del micro en el día (no solo el más rico) y los escala
                # richest-first hasta cerrar el piso o agotar el presupuesto kcal del día → cierra déficits que un
                # solo ingrediente (factor≤MAX_SCALE) no alcanza. Si tras agotar contribuyentes/budget el día sigue
                # bajo el piso, lo LOGUEA (distingue "cerrado" de "closer insuficiente" → evita falsa confianza).
                contributors = []  # (contrib, meal, ing_idx, ing_str, kcal_now)
                day_total = 0.0
                for _m in (_d.get("meals") or []):
                    if not isinstance(_m, dict):
                        continue
                    ings = _m.get("ingredients")
                    if not isinstance(ings, list):
                        continue
                    # [P2-MICRO-CLOSER-RAW-BASIS · 2026-07-02] (audit v3 micros GAP-3) MEDIR sobre la misma
                    # base que el panel/intake real: `ingredients_raw` preferido (micronutrients.py:289 —
                    # display como "¾ lonja de queso" no resuelve). Antes déficit Y headroom del UL se
                    # computaban sobre display: sub-resolución → sobre-escala (acotada) y, peor, el guard de
                    # toxicidad UL medía en la base equivocada. La ESCALA sigue aplicándose a AMBAS formas
                    # (display + raw-sync abajo, mismo factor). Requiere alineación posicional (len ==);
                    # sin raw alineado → display (comportamiento previo). tooltip-anchor: P2-MICRO-CLOSER-RAW-BASIS
                    _raw_m = _m.get("ingredients_raw")
                    _raw_ok = isinstance(_raw_m, list) and len(_raw_m) == len(ings)
                    for i, ing in enumerate(ings):
                        if not isinstance(ing, str):
                            continue
                        _meas = _raw_m[i] if (_raw_ok and isinstance(_raw_m[i], str) and _raw_m[i].strip()) else ing
                        try:
                            mic = db.micros_from_ingredient_string(_meas)
                        except Exception:
                            mic = None
                        if not mic:
                            continue
                        c = mic.get(ing_key)
                        if not c or c <= 0:
                            continue
                        day_total += float(c)
                        try:
                            _mac = db.macros_from_ingredient_string(_meas)
                            _kc = float(_mac.get("kcal") or 0) if _mac else 0.0
                        except Exception:
                            _kc = 0.0
                        contributors.append((float(c), _m, i, ing, _kc))
                if day_total >= floor:
                    continue
                # [P1-MICRO-SEED · 2026-07-04] día SIN portador del micro → nada que escalar
                # (el residual quedaba abierto → banner micro_worst_day). Siembra UNA línea
                # pequeña del catálogo (alergia/dislike-aware) y la registra como contribuyente;
                # el loop richest-first de abajo la escala hacia el piso dentro del presupuesto.
                # [P1-MICRO-SEED-CAPPED · 2026-07-05] v2: también con portadores PROFUNDAMENTE
                # cortos (< MICRO_SEED_BELOW_RATIO × piso) — el escalado acotado por MAX_SCALE/
                # kcal no cierra gaps 2-3× (caso vivo 08ed036d: sardinas presentes, omega-3 0.44×).
                # Anti-doble-siembra: si el día ya tiene comida sembrada para este micro, skip.
                _had_carriers = bool(contributors)
                _already_seeded = any(
                    isinstance(m, dict) and m.get("_micro_seed_applied") == k
                    for m in (_d.get("meals") or [])
                )
                _seed_trigger = (not contributors) or (
                    MICRO_SEED_BELOW_RATIO > 0 and day_total < MICRO_SEED_BELOW_RATIO * floor
                )
                # [P1-MICRO-SEED-DENSITY · 2026-07-05] guard 30→25: linaza (53 kcal) dejaba 67 de
                # los 120 del budget — la 2ª semilla del día (girasol 58) debe caber.
                # [P1-MICRO-BUDGET-NONFAT-FIRST · 2026-07-07] micro grasa-basado SIN PORTADOR y sin budget
                # compartido → puede sembrar desde la reserva dedicada. Restringido a `not _had_carriers`:
                # el caso CON portador (deeply-short) lo cierra el fatswap escalando el portador existente
                # con su propio budget → la reserva es SOLO para el caso no-carrier (que el fatswap no cubre).
                _seed_from_reserve = (k in _FAT_BASED_MICROS and not _had_carriers
                                      and kcal_budget_left <= MICRO_SEED_MIN_BUDGET_KCAL
                                      and _fat_seed_reserve > MICRO_SEED_MIN_BUDGET_KCAL)
                if _seed_trigger and not _already_seeded and MICRO_SEED_ENABLED \
                        and k in _MICRO_SEED_SOURCES \
                        and (kcal_budget_left > MICRO_SEED_MIN_BUDGET_KCAL or _seed_from_reserve):
                    try:
                        from constants import strip_accents as _sa_seed
                        _seed_dislikes = {_sa_seed(str(x).strip().lower())
                                          for x in (_fd.get("dislikes") or []) if str(x).strip()}
                        _seed_line = None
                        for _cand in _MICRO_SEED_SOURCES[k]:
                            _cand_low = _sa_seed(_cand.lower())
                            if any(dk and dk in _cand_low for dk in _seed_dislikes):
                                continue
                            if _fd.get("allergies"):
                                try:
                                    if _scan_allergen_violations(
                                        {"days": [{"meals": [{"ingredients": [_cand]}]}]},
                                        _fd.get("allergies"),
                                    ):
                                        continue
                                except Exception:
                                    continue  # conservador: duda → no sembrar este candidato
                            # [P3-5 · 2026-07-07] guard de dieta (veg/vegan/pescetariano): moot hoy (seeds
                            # plant-based) pero fail-secure PREVENTIVO si algún día entra un seed animal
                            # (hígado→hierro, pescado→omega-3). Espejo del allergen-scan de arriba.
                            _seed_diet = _fd.get("dietType") or _fd.get("diet_type")
                            if _seed_diet:
                                try:
                                    if _scan_diet_violations(
                                        {"days": [{"meals": [{"ingredients": [_cand]}]}]}, _seed_diet):
                                        continue
                                except Exception:
                                    continue  # conservador: duda → no sembrar
                            _seed_line = _cand
                            break
                        if _seed_line:
                            _seed_cands = [m for m in (_d.get("meals") or [])
                                           if isinstance(m, dict) and isinstance(m.get("ingredients"), list)]
                            if MICRO_SEED_SPREAD_ENABLED and _seed_cands:
                                # [P2-SEED-MEAL-SELECTION · 2026-07-05] repartir: merienda sin seed →
                                # meal sin seed → merienda → cualquiera; gana la de MENOS kcal (headroom).
                                # [P2-MICRO-SEED-VITA · 2026-07-06] seeds SALADOS (zanahoria/auyama) →
                                # pool preferido almuerzo/cena (no una merienda dulce).
                                if k in _MICRO_SEED_SAVORY_KEYS:
                                    _seed_mers = [m for m in _seed_cands
                                                  if any(t in str(m.get("meal", "")).lower()
                                                         for t in ("almuerzo", "cena", "comida"))]
                                    # [P3-3 · 2026-07-07] seed SALADO (zanahoria/auyama/espinaca) sin comida
                                    # salada (día solo con meriendas dulces) → NO sembrar: mejor el residual
                                    # honesto que "zanahoria rallada" en un yogurt-con-fruta. Pool = solo
                                    # saladas (sin fallback a cualquier meal → _seed_pool vacío → skip).
                                    _seed_pool = ([m for m in _seed_mers if not m.get("_micro_seed_applied")]
                                                  or _seed_mers)
                                else:
                                    _seed_mers = [m for m in _seed_cands
                                                  if "merienda" in str(m.get("meal", "")).lower()]
                                    _seed_pool = ([m for m in _seed_mers if not m.get("_micro_seed_applied")]
                                                  or [m for m in _seed_cands if not m.get("_micro_seed_applied")]
                                                  or _seed_mers or _seed_cands)
                                _seed_meal = (min(_seed_pool, key=lambda m: _meal_macro_num(m.get("cals")))
                                              if _seed_pool else None)
                            else:
                                _seed_meal = next(
                                    (m for m in _seed_cands
                                     if "merienda" in str(m.get("meal", "")).lower()),
                                    None,
                                ) or (_seed_cands[0] if _seed_cands else None)
                            if _seed_meal is not None:
                                # [P3-2 · 2026-07-07] resolver el micro ANTES de appendear: un seed que no
                                # resuelve en el catálogo (drift) dejaba una línea FANTASMA con nota 🌱 (0
                                # micros), descontaba budget y ponía _micro_seed_applied (bloqueaba re-seed)
                                # → el gap quedaba abierto Y silencioso. Fail-secure: no resuelve → no sembrar.
                                try:
                                    _seed_mic = db.micros_from_ingredient_string(_seed_line) or {}
                                    _c_seed = float(_seed_mic.get(ing_key) or 0.0)
                                except Exception:
                                    _c_seed = 0.0
                                try:
                                    _seed_mac = db.macros_from_ingredient_string(_seed_line) or {}
                                    _kc_seed = float(_seed_mac.get("kcal") or 0.0)
                                except Exception:
                                    _kc_seed = 0.0
                                if _c_seed <= 0:
                                    logger.info(f"🌱 [P1-MICRO-SEED] seed '{_seed_line}' de '{k}' no resuelve "
                                                f"en el catálogo → NO sembrado (fail-secure vs catalog-drift).")
                                else:
                                    _seed_meal["ingredients"].append(_seed_line)
                                    _seed_raw = _seed_meal.get("ingredients_raw")
                                    if isinstance(_seed_raw, list):
                                        _seed_raw.append(_seed_line)  # preserva alineación posicional
                                    try:
                                        _truth_up_meal_macros_from_strings(_seed_meal, db)
                                    except Exception:
                                        pass
                                    contributors.append((
                                        _c_seed, _seed_meal,
                                        len(_seed_meal["ingredients"]) - 1, _seed_line, _kc_seed,
                                    ))
                                    day_total += _c_seed
                                    # [P1-MICRO-BUDGET-NONFAT-FIRST · 2026-07-07] descuenta del budget correcto:
                                    # la reserva dedicada si el seed grasa-basado no tenía budget compartido.
                                    if _seed_from_reserve:
                                        _fat_seed_reserve -= _kc_seed
                                    else:
                                        kcal_budget_left -= _kc_seed
                                    _seed_meal["_micro_seed_applied"] = k
                                    # [P2-SEED-STEP-NOTE · 2026-07-05] la semilla también vive en los pasos.
                                    if MICRO_SEED_STEP_NOTE_ENABLED:
                                        _rec_seed = _seed_meal.get("recipe")
                                        # [P3-4 · 2026-07-07] coacciona recipe a lista (None/str) para no
                                        # dropear la nota 🌱 en silencio (→ ingrediente sembrado sin mención).
                                        if not isinstance(_rec_seed, list):
                                            _rec_seed = [str(_rec_seed)] if (_rec_seed and str(_rec_seed).strip()) else []
                                        # [P2-MICRO-SEED-VITA · 2026-07-06] seeds salados no se "espolvorean".
                                        _seed_verb = ("acompaña el plato con" if k in _MICRO_SEED_SAVORY_KEYS
                                                      else "espolvorea")
                                        # [P3-RECIPE-POLISH-4 · 2026-07-06] en BEBIDAS (batido/licuado) no
                                        # hay "plato" → tail "al servir".
                                        _seed_is_drink = any(
                                            t in _sa_seed(str(_seed_meal.get("name", "")).lower())
                                            for t in ("batido", "batida", "licuado", "smoothie", "jugo"))
                                        _seed_tail = ("" if k in _MICRO_SEED_SAVORY_KEYS
                                                      else (" al servir" if _seed_is_drink
                                                            else " sobre el plato al servir"))
                                        # [P3-9 · 2026-07-07] la nota 🌱 está EXCLUIDA del qty-sync (por
                                        # diseño) → si embebe la cantidad del seed ("50 g de zanahoria
                                        # rallada"), el closer la escala (→65g) y humanize reforma la
                                        # LÍNEA de ingrediente ("½ zanahoria") mientras la nota queda
                                        # congelada = triple divergencia (nota "¾ zanahoria (65g)" vs
                                        # display "½ zanahoria" vs raw "65g", plan vivo 766893f4). La
                                        # cantidad vive en la línea de ingrediente (fuente de verdad); la
                                        # nota solo NOMBRA el alimento. Strip del lead qty/unit/"de".
                                        _seed_food = _re.sub(
                                            r"^\s*\d+(?:[.,]\d+)?\s*(?:g|gr|gramos|ml|kg|taza|tazas|"
                                            r"cda|cdas|cdta|cdtas|unidad|unidades)?\s*(?:de\s+)?", "",
                                            _seed_line, flags=_re.IGNORECASE).strip() or _seed_line
                                        _seed_meal["recipe"] = _insert_step_before_montaje(
                                            _rec_seed,
                                            f"🌱 Nota del Nutricionista AI: {_seed_verb} {_seed_food}"
                                            f"{_seed_tail} — cierra tu "
                                            f"{_MICRO_SEED_HUMAN.get(k, k)} del día.")
                                    adjustments += 1
                                    _seed_why = ("día sin portador" if not _had_carriers else
                                                 f"portadores muy cortos ({day_total - _c_seed:.2g} < "
                                                 f"{MICRO_SEED_BELOW_RATIO}×{floor:.2g})")
                                    logger.info(f"🌱 [P1-MICRO-SEED] {_seed_why} de '{k}' → "
                                                f"sembrado '{_seed_line}' (el closer lo escala al piso)")
                    except Exception as _seed_e:
                        logger.debug(f"[P1-MICRO-SEED] seed no-op: {type(_seed_e).__name__}: {_seed_e}")
                elif _seed_trigger and _already_seeded and MICRO_SEED_REINFORCE_ENABLED \
                        and MICRO_SEED_ENABLED and k in _MICRO_SEED_SOURCES:
                    # [P1-MICRO-SEED-DENSITY · 2026-07-05] REFUERZO post-erosión: el día ya fue
                    # sembrado para este micro pero sigue bajo el umbral (el motor/quantize
                    # erosionó la semilla, o el gap era 2-3×). UNA re-escalada de la línea
                    # sembrada (cap 30 g; una vez por día/micro vía _micro_seed_reinforced).
                    # No se toca day_total/contributors: el loop de escala de abajo y el
                    # recompute final del panel (P2-1) miden la verdad fresca.
                    try:
                        import re as _re_rs
                        _cand_foods = tuple(
                            c.split(" de ", 1)[1].lower() for c in _MICRO_SEED_SOURCES[k]
                            if " de " in c
                        )
                        for _rm in (_d.get("meals") or []):
                            if not (isinstance(_rm, dict) and _rm.get("_micro_seed_applied") == k):
                                continue
                            if _rm.get("_micro_seed_reinforced") == k:
                                break  # ya reforzado — no crecer sin límite
                            _r_ings = _rm.get("ingredients")
                            if not isinstance(_r_ings, list):
                                break
                            for _ri, _rline in enumerate(_r_ings):
                                if not isinstance(_rline, str) or not any(
                                        cf in _rline.lower() for cf in _cand_foods):
                                    continue
                                _m_g = _re_rs.match(r"^\s*(\d+(?:[.,]\d+)?)\s*g\b", _rline)
                                if not _m_g:
                                    continue
                                _g_now = float(_m_g.group(1).replace(",", "."))
                                _g_new = min(30.0, max(_g_now * 1.8, _g_now + 8.0))
                                if _g_new <= _g_now + 0.5:
                                    break
                                _new_line = _re_rs.sub(r"^\s*\d+(?:[.,]\d+)?\s*g",
                                                       f"{int(round(_g_new))} g", _rline, count=1)
                                _r_ings[_ri] = _new_line
                                _r_raw = _rm.get("ingredients_raw")
                                if isinstance(_r_raw, list) and _ri < len(_r_raw) \
                                        and isinstance(_r_raw[_ri], str):
                                    _r_raw[_ri] = _new_line
                                try:
                                    _truth_up_meal_macros_from_strings(_rm, db)
                                except Exception:
                                    pass
                                _rm["_micro_seed_reinforced"] = k
                                adjustments += 1
                                # actualizar el contributor correspondiente: sin esto, el loop de
                                # escala de abajo re-escala desde el string VIEJO (10 g × MAX_SCALE)
                                # y PISA el refuerzo (18→16 g, medido en test).
                                try:
                                    _mic_rs = db.micros_from_ingredient_string(_new_line) or {}
                                    _c_rs = float(_mic_rs.get(ing_key) or 0.0)
                                except Exception:
                                    _c_rs = 0.0
                                for _ci, (_cc, _cm, _cix, _cs, _ckc) in enumerate(contributors):
                                    if _cm is _rm and _cix == _ri:
                                        if _c_rs > _cc:
                                            day_total += (_c_rs - _cc)
                                        contributors[_ci] = (
                                            _c_rs if _c_rs > 0 else _cc, _cm, _cix, _new_line, _ckc)
                                        break
                                logger.info(f"🌱 [P1-MICRO-SEED] refuerzo post-erosión de '{k}': "
                                            f"semilla re-escalada a {int(round(_g_new))} g "
                                            f"(el día seguía bajo el umbral).")
                                break
                            break
                    except Exception as _rs_e:
                        logger.debug(f"[P1-MICRO-SEED] refuerzo no-op: {type(_rs_e).__name__}: {_rs_e}")
                if not contributors:
                    # [Sd-P2-c / P2-MICRO-RESIDUAL-NOCARRIER · 2026-07-07] día SIN portador y sin siembra
                    # materializada (micro no-sembrable como hierro/folato, o el seed no entró por alérgeno/
                    # budget) → el closer NO pudo ni intentar. Antes se saltaba SILENCIOSO (el residual log de
                    # abajo solo cubría el caso has-carrier-but-short) → ops ciego a la limitación de MAYOR
                    # consecuencia. Telemetría del gap estructural (el banner ya lo ve el user).
                    _why_nc = ("micro no-sembrable" if k not in _MICRO_SEED_SOURCES
                               else "seed no materializó (alérgeno/budget/dislike)")
                    logger.info(f"🧪 [P2-MICRO-CLOSER-RESIDUAL] {k}: día SIN portador ({_why_nc}; piso {floor:.2g}) "
                                f"→ no_carrier_no_seed — el closer no pudo actuar.")
                    continue
                contributors.sort(key=lambda t: t[0], reverse=True)  # richest-first
                for contrib, meal, idx, ing_str, kcal_now in contributors:
                    if day_total >= floor or kcal_budget_left <= 1.0:
                        break
                    # [P2-MICRO-CLOSER-CEILINGS] contribuyente de riesgo para un techo activo → saltar.
                    try:
                        from constants import strip_accents as _sa_ceil
                        if _ceiling_risky_contributor(k, _sa_ceil(str(ing_str).lower())):
                            continue
                    except Exception:
                        pass
                    deficit = floor - day_total
                    factor = min(MICRONUTRIENT_CLOSER_MAX_SCALE, 1.0 + (deficit / contrib))
                    if kcal_now > 0:
                        factor = min(factor, 1.0 + (kcal_budget_left / kcal_now))  # presupuesto kcal COMPARTIDO del día
                    if _ul is not None and _ul > 0 and contrib > 0:
                        # [P1-MICRO-CLOSER-COVERAGE] no escalar el total del micro del día por encima de su UL
                        # (toxicidad: hierro 45mg / zinc 40mg). headroom = UL − total actual del micro.
                        headroom = _ul - day_total
                        if headroom <= 0:
                            break  # el día ya está en/sobre el UL para este micro → no escalar más
                        factor = min(factor, 1.0 + (headroom / contrib))
                    if factor <= 1.0 + 1e-3:
                        continue  # este contribuyente no aporta margen útil → probar el siguiente
                    # [P1-CLOSER-LINE-CLAMP · 2026-07-05] techo ABSOLUTO de la línea (el factor
                    # por-pasada compone entre pasadas → "47.5 tallos de apio" en vivo). Si la
                    # línea ya está en su techo físico, se salta; si el factor la excedería, se
                    # recorta al techo. Semillas/frutos secos (linaza/girasol/almendras/maní...):
                    # 40.0 g — densos en kcal/grasa. Tokens SSOT `_SEED_NUT_TOKENS`, compartidos
                    # con la protección del re-trim de grasas (P1-FATS-POSTCLOSER-RELEVEL).
                    try:
                        _g_now = float(db.grams_from_ingredient_string(ing_str) or 0.0)
                    except Exception:
                        _g_now = 0.0
                    if _g_now > 0:
                        _line_low = str(ing_str).lower()
                        _line_cap = 40.0 if any(t in _line_low for t in _SEED_NUT_TOKENS) \
                            else float(MICRO_CLOSER_LINE_MAX_G)
                        if _g_now >= _line_cap:
                            continue  # línea en su techo vitalicio → probar el siguiente
                        factor = min(factor, _line_cap / _g_now)
                        if factor <= 1.0 + 1e-3:
                            continue
                    new_ing = _resc(ing_str, factor)
                    if not new_ing or new_ing == ing_str:
                        continue
                    meal["ingredients"][idx] = new_ing
                    # [P1-MICRO-CLOSER-RAW-SYNC · 2026-06-29] El panel de micros (micronutrients.py:289),
                    # la lista de compras y el truth-up de macros LEEN `ingredients_raw` (prefieren raw sobre
                    # display). Sin reescalar el raw por el MISMO factor, el cierre del closer era INVISIBLE al
                    # panel recomputado, al PDF y a la lista — los gramos extra los "comía" el raw sin escalar y
                    # el reporte seguía mostrando el gap abierto. Espejo del closer de proteína (g_o.py:12052-12057)
                    # y del reconcile de macros (g_o.py:15924-15926), que escalan AMBAS formas. tooltip-anchor: P1-MICRO-CLOSER-RAW-SYNC
                    _raw = meal.get("ingredients_raw")
                    if isinstance(_raw, list) and idx < len(_raw) and isinstance(_raw[idx], str):
                        try:
                            _new_raw = _resc(_raw[idx], factor)
                            if _new_raw:
                                meal["ingredients_raw"][idx] = _new_raw
                        except Exception:
                            pass
                    try:
                        _truth_up_meal_macros_from_strings(meal, db)
                    except Exception:
                        pass
                    if kcal_now > 0:
                        kcal_budget_left -= kcal_now * (factor - 1.0)
                    day_total += contrib * (factor - 1.0)  # el micro sube por el aporte reescalado
                    adjustments += 1
                # [P1-MICRO-FATSWAP · 2026-07-06] (banner vivo plan 6ffffd39) micros GRASA-basados
                # (omega-3/vit E) cortos porque el budget kcal compartido se agotó: sus portadores
                # SON grasas y el día suele estar ya al techo de grasas → nunca hay headroom. El
                # fatswap concede presupuesto EXTRA propio, escala el portador más rico (frescos,
                # con los mismos techos de línea) y ejecuta el ESPEJO inmediato: re-trim de grasas
                # del día a target (protege portadores _SEED_NUT_TOKENS, recorta grasa genérica)
                # → intercambio neto grasa-genérica→portadora. tooltip-anchor: P1-MICRO-FATSWAP
                if (day_total < floor and MICRO_FATSWAP_ENABLED and k in _FAT_BASED_MICROS):
                    try:
                        _fs_budget = float(MICRO_FATSWAP_EXTRA_KCAL)
                        _fs_scaled = False
                        _fs_cands = []
                        for _fm in (_d.get("meals") or []):
                            if not isinstance(_fm, dict) or not isinstance(_fm.get("ingredients"), list):
                                continue
                            for _fi, _fing in enumerate(_fm["ingredients"]):
                                try:
                                    _fmic = db.micros_from_ingredient_string(str(_fing)) or {}
                                    _fc = float(_fmic.get(ing_key) or 0.0)
                                except Exception:
                                    _fc = 0.0
                                if _fc > 0:
                                    _fs_cands.append((_fc, _fm, _fi, str(_fing)))
                        _fs_cands.sort(key=lambda t: -t[0])
                        # [Sd-P2-b / P2-FATSWAP-BAND-GUARD · 2026-07-07] budget de GRASA del fatswap: la grasa
                        # que AÑADE ≤ headroom de banda + grasa movible-no-protegida (lo que el mirror-trim SÍ
                        # puede recortar). Sin esto, en día nut/seed-heavy (toda la grasa en portadores
                        # protegidos) el fatswap REVIENTA la banda (el trim no tiene qué quitar → banner
                        # low_band_macro:fats en plan limpio). Sin fat-target → sin cap.
                        _fs_fat_tgt = _meal_macro_num((plan.get("macros") or {}).get("fats")) or 0.0
                        _fs_fat_budget = None
                        _fs_fat_added = 0.0
                        if _fs_fat_tgt > 0:
                            try:
                                from constants import strip_accents as _sa_fsb
                            except Exception:
                                def _sa_fsb(_x):
                                    return _x
                            _fs_day_fat = sum(_meal_macro_num(_mm.get("fats"))
                                              for _mm in (_d.get("meals") or []) if isinstance(_mm, dict))
                            _fs_movable = 0.0
                            for _mm in (_d.get("meals") or []):
                                if not isinstance(_mm, dict) or not isinstance(_mm.get("ingredients"), list):
                                    continue
                                for _mi in _mm["ingredients"]:
                                    _mil = str(_mi)
                                    if _ingredient_macro_group(_mil, db) != "fats":
                                        continue
                                    _mil_sa = _sa_fsb(_mil.lower())
                                    if any(_sa_fsb(_t) in _mil_sa for _t in _SEED_NUT_TOKENS):
                                        continue  # portador protegido → el trim no lo recorta
                                    _fs_movable += float((db.macros_from_ingredient_string(_mil) or {}).get("fats") or 0.0)
                            _fs_fat_budget = max(0.0, _fs_fat_tgt * (1.0 + FATS_POSTCLOSER_RELEVEL_TOL)
                                                 - _fs_day_fat) + _fs_movable
                        for _fc, _fm, _fi, _fing in _fs_cands:
                            if day_total >= floor or _fs_budget <= 5.0:
                                break
                            # [P1-MICRO-BUDGET-NONFAT-FIRST · 2026-07-07] el reorder saca los micros
                            # grasa-basados del budget compartido → el fatswap es ahora su path PRINCIPAL de
                            # escalado y DEBE honrar el mismo guard clínico que el loop principal (12234): en
                            # dislipidemia/HTA jamás escalar queso/mantequilla (satfat) para cerrar vitE.
                            try:
                                from constants import strip_accents as _sa_fs
                                if _ceiling_risky_contributor(k, _sa_fs(str(_fing).lower())):
                                    continue
                            except Exception:
                                pass
                            try:
                                _g_now = float(db.grams_from_ingredient_string(_fing) or 0.0)
                            except Exception:
                                _g_now = 0.0
                            _line_cap = 40.0 if any(t in _fing.lower() for t in _SEED_NUT_TOKENS) \
                                else float(MICRO_CLOSER_LINE_MAX_G)
                            if _g_now <= 0 or _g_now >= _line_cap:
                                continue
                            try:
                                _fmac = db.macros_from_ingredient_string(_fing) or {}
                                _fk = float(_fmac.get("kcal") or 0.0)
                            except Exception:
                                _fk = 0.0
                            factor = min(MICRONUTRIENT_CLOSER_MAX_SCALE,
                                         1.0 + (floor - day_total) / _fc,
                                         _line_cap / _g_now)
                            if _fk > 0:
                                factor = min(factor, 1.0 + _fs_budget / _fk)
                            # [Sd-P2-b] cap por banda de grasa: la grasa que este escalado añade
                            # (fat_portador × (factor−1)) no debe exceder lo que el trim puede compensar.
                            _cand_fat = float((_fmac or {}).get("fats") or 0.0)
                            if _fs_fat_budget is not None and _cand_fat > 0:
                                _fat_room = _fs_fat_budget - _fs_fat_added
                                if _fat_room <= 0:
                                    break  # sin headroom de grasa → parar (no reventar la banda)
                                factor = min(factor, 1.0 + _fat_room / _cand_fat)
                            if factor <= 1.0 + 1e-3:
                                continue
                            _new_f = _resc(_fing, factor)
                            if not _new_f or _new_f == _fing:
                                continue
                            _fm["ingredients"][_fi] = _new_f
                            _fraw = _fm.get("ingredients_raw")
                            if isinstance(_fraw, list) and _fi < len(_fraw) \
                                    and isinstance(_fraw[_fi], str):
                                try:
                                    _nr = _resc(_fraw[_fi], factor)
                                    if _nr:
                                        _fraw[_fi] = _nr
                                except Exception:
                                    pass
                            try:
                                _truth_up_meal_macros_from_strings(_fm, db)
                            except Exception:
                                pass
                            if _fk > 0:
                                _fs_budget -= _fk * (factor - 1.0)
                            if _fs_fat_budget is not None:
                                _fs_fat_added += _cand_fat * (factor - 1.0)
                            day_total += _fc * (factor - 1.0)
                            adjustments += 1
                            _fs_scaled = True
                        if _fs_scaled:
                            _fs_tf = _meal_macro_num((plan.get("macros") or {}).get("fats"))
                            _fs_trimmed = False
                            if _fs_tf and float(_fs_tf) > 0:
                                try:
                                    _fs_trimmed = _trim_day_fats_to_target(
                                        (_d.get("meals") or []), float(_fs_tf), db,
                                        tol=FATS_POSTCLOSER_RELEVEL_TOL)
                                except Exception:
                                    pass
                            # [Sd-P2-b] distinguir "no-necesario" (grasa ya en banda) de "NO-PUDO"
                            # (movable<=0, grasa en portadores protegidos → banda abierta pese al trim). El
                            # 'no-necesario' viejo conflaba ambos → un blowout se leía como éxito.
                            _fs_over = False
                            if _fs_tf and float(_fs_tf) > 0:
                                _fs_day_fat_post = sum(_meal_macro_num(_mm.get("fats"))
                                                       for _mm in (_d.get("meals") or []) if isinstance(_mm, dict))
                                _fs_over = _fs_day_fat_post > float(_fs_tf) * (1.0 + FATS_POSTCLOSER_RELEVEL_TOL)
                            _fs_state = ("aplicado" if _fs_trimmed else
                                         ("NO-PUDO: grasa en portadores protegidos, banda abierta" if _fs_over
                                          else "no-necesario"))
                            logger.info(f"🔄 [P1-MICRO-FATSWAP] '{k}' cerrado con presupuesto extra "
                                        f"(≈{day_total:.1f} vs piso {floor:.1f}) + re-trim espejo de "
                                        f"grasas del día ({_fs_state}).")
                    except Exception as _fs_e:
                        logger.warning(f"[P1-MICRO-FATSWAP] no-op: {type(_fs_e).__name__}: {_fs_e}")
                if day_total < floor:
                    logger.info(f"🧪 [P2-MICRO-CLOSER-RESIDUAL] {k}: el día sigue bajo el piso tras el cierre "
                                f"(≈{day_total:.1f} < {floor:.1f}); closer insuficiente (budget/UL/contribuyentes)")
        if adjustments:
            logger.info(
                f"🧪 [P1-MICRONUTRIENT-CLOSER] {adjustments} ajuste(s) de micros alcanzables "
                f"(escala determinista de ingrediente existente; micros={sorted(floors)})"
            )
        return adjustments
    except Exception as _mc_e:
        logger.warning(f"[P1-MICRONUTRIENT-CLOSER] falló (no bloquea): {type(_mc_e).__name__}: {_mc_e}")
        return 0


def _surgical_promote_blocked_reason(new_plan_result: dict, form_data: dict):
    """[P1-SURGICAL-PROMOTE-BYPASS · 2026-06-22] (audit fresco P1-2) SSOT testeable del gate de
    promoción de `surgical_marker_regen_node`. Devuelve el motivo (str) por el que el plan
    post-surgical NO debe promoverse a 'approved'/review_passed=True, o `None` si es seguro promover.

    Re-usa los MISMOS escáneres deterministas del review:
      - `_protein_floor_shortfall` (exento renal — su techo KDIGO manda; subir proteína sería iatrogénico).
      - `_scan_diet_violations` (producto animal en plan veg*), gateado por `DIET_HARD_GUARD`.

    Razón: la corrección LLM del surgical regen puede introducir un déficit de proteína (observado en
    vivo) o un producto animal prohibido. Si se promueve un plan así a 'approved', el snapshot sobrevive
    a la re-review y `_swap_to_best_attempt_if_better` restaura review_passed=True → los backstops
    fail-hard (gateados por `not review_passed`) NO corren → plan degradado entregado SIN banner. Si
    este helper devuelve un motivo, el nodo NO promueve y deja el snapshot 'approved' pre-surgical como
    best. Fail-safe: un error del escáner devuelve un motivo (conservador → no promover).
    tooltip-anchor: P1-SURGICAL-PROMOTE-BYPASS"""
    if not isinstance(new_plan_result, dict):
        return None
    try:
        _renal_capped = bool((new_plan_result.get("renal_protein_cap") or {}).get("applied"))
        _short = _protein_floor_shortfall(new_plan_result, renal_capped=_renal_capped, form_data=form_data)
        if _short:
            return "piso de proteína: " + "; ".join(f"Día {d}: {p}g de {t}g" for d, p, t in _short[:4])
        if DIET_HARD_GUARD:
            _viol = _scan_diet_violations(new_plan_result, form_data.get("dietType") if isinstance(form_data, dict) else None)
            if _viol:
                return "dieta veg*: " + "; ".join(f"'{_ing}' ({_cat}) en {_mn}" for _mn, _ing, _cat in _viol[:4])
    except Exception as _e:
        return f"error de re-validación: {type(_e).__name__}: {_e}"
    return None


# [P1-DM2-GLYCEMIC-ONLY · 2026-06-15] (gap-audit P1-1) Marcadores (acent-stripped) para clasificar si un
# rechazo CRÍTICO del revisor es PURAMENTE glucémico (seguro de degradar a 'high' para diabéticos) vs. una
# preocupación de seguridad de otro tipo (que debe ir al fallback). Sesgo conservador: sin señal glucémica
# positiva → NO se degrada (se preserva el critical → fallback).
_GLYCEMIC_MARKERS = (
    # [post-review 2026-06-15] 'jugo'/'zumo'/'soda'/'carbo' eran substrings demasiado amplios (jugo
    # gástrico, bicarbonato de soda, carbonatado) → anclados a contexto azucarado.
    "glucos", "glucem", "glicem", "glycemic", "azucar", "indice glucemico", "carga glucemica",
    "ig alto", "alto ig", "miel", "jarabe", "almibar", "sirope", "melaza", "panela", "dulce",
    "postre", "jugo de fruta", "jugo natural", "jugo azucarado", "jugo de china", "jugo de naranja",
    "refresco", "platano", "guineo maduro", "carbohidrato simple", "carbohidratos simples",
    "harina refinada", "pan blanco", "arroz blanco", "fructosa", "sacarosa", "mermelada",
    "bebida azucarada", "sugar", "carbohidrato", "indice glicemico",
)
# [post-review 2026-06-15] (1) crudo/cruda ANCLADO a frases food-safety inequívocas (el bare 'crud*'
# tragaba 'miel cruda'/'jugo crudo'/'vegetales crudos' glucémicos → falso fallback del diabético). (2) Se
# añaden concerns AGUDAS no-glucémicas: interacción farmacológica (warfarina/metformina) + renal/iatrogénica.
# (3) NO se añaden sodio/colesterol/grasa-saturada: HTA y dislipidemia son advisory-by-decision (CLAUDE.md
# G9 — NO hard-gate a fallback); para esas, degradar+banner+sustitución es el comportamiento correcto, y
# bloquearlas aquí subiría el fallback indebidamente.
_NON_GLYCEMIC_SAFETY_MARKERS = (
    "alergi", "alerg", "anafilax", "vegano", "vegana", "vegetarian",
    "huevo crudo", "huevos crudos", "carne cruda", "pollo crudo", "pescado crudo", "res cruda",
    "ceviche", "sin cocer", "sin coccion", "salmonel", "listeria", "embaraz", "lactancia", "celiac",
    "intoxic", "toxic", "mercurio",
    "interaccion", "medicament", "metformina", "warfarina", "anticoagulante",
    "renal", "potasio", "fosforo",
)


def _critical_is_purely_glycemic(issues) -> bool:
    """[P1-DM2-GLYCEMIC-ONLY · 2026-06-15] True SOLO si los issues del rechazo crítico evidencian una
    preocupación glucémica Y ninguna otra de seguridad (alérgeno/dieta/food-safety/embarazo/celíaca).
    Conservador: sin señal glucémica positiva → False (no degradar). Anchor: P1-DM2-GLYCEMIC-ONLY."""
    try:
        from constants import strip_accents
    except Exception:
        def strip_accents(s):
            import unicodedata
            return "".join(c for c in unicodedata.normalize("NFKD", str(s)) if not unicodedata.combining(c))
    glyc = False
    for raw in (issues or []):
        t = strip_accents(str(raw).lower())
        if any(b in t for b in _NON_GLYCEMIC_SAFETY_MARKERS):
            return False
        if any(g in t for g in _GLYCEMIC_MARKERS):
            glyc = True
    return glyc


# [P1-BARIATRIC-CRITICAL-RETRY · 2026-06-28] Marcas de criticals bariátricos NO-regenerables: concerns CONTEXTUALES que
# NO cambian entre intentos (embarazo/lactancia/mercurio/celíaca/interacción farmacológica). allergen/renal/diet/schema ya
# se excluyen por flag aguas arriba. NO incluye porción/volumen/grano-crudo/especia/azúcar (esas SÍ las corrige el LLM).
# Marcas sin acento (los issues se comparan accent-stripped).
_BARIATRIC_NONREGENERABLE_MARKERS = (
    "embaraz", "lactancia", "mercurio", "celiac",
    "interaccion", "medicament", "warfarina", "metformina", "anticoagulante",
)


def _critical_is_bariatric_regenerable(issues) -> bool:
    """[P1-BARIATRIC-CRITICAL-RETRY] True si el crítico bariátrico es una violación de ELECCIÓN DE COMIDA que un retry con
    feedback puede corregir (porción/volumen/grano-crudo/especia/azúcar), y NINGUNA marca contextual no-regenerable
    (embarazo/mercurio/celíaca/interacción). Conservador: issues vacío → False (no degradar → fallback)."""
    if not issues:
        return False
    try:
        from constants import strip_accents
    except Exception:
        def strip_accents(s):
            import unicodedata
            return "".join(c for c in unicodedata.normalize("NFKD", str(s)) if not unicodedata.combining(c))
    for raw in issues:
        t = strip_accents(str(raw).lower())
        if any(m in t for m in _BARIATRIC_NONREGENERABLE_MARKERS):
            return False
    return True


# [P3-FOOD-SAFETY · 2026-06-13] Seguridad alimentaria determinista: el huevo es un alimento
# TCS (Time/Temperature Control for Safety); crudo/poco cocido = vector directo de Salmonella
# enteritidis (CDC/FDA Food Code lo desaconsejan sin pasteurizar). Hallazgo CRÍTICO de la
# auditoría clínica multi-agente (plan 11d17452: ½ huevo crudo LICUADO en un batido +
# 1¼ huevos sin paso de cocción en un wrap). Simétrico al allergen guard: el revisor LLM
# puede dejar pasar huevo crudo, y el solver/top-up podría AÑADIRLO a una preparación fría;
# este guard determinista nunca sirve huevo crudo sin una mitigación explícita.
_RAW_EGG_TERMS = ("huevo", "huevos", "clara", "claras", "yema", "yemas")
# Preparaciones LICUADAS/FRÍAS donde el huevo queda inequívocamente CRUDO (no hay cocción
# posible aguas abajo): un batido no se cocina. Aquí el riesgo es máximo y el fix es fuerte.
_NO_COOK_BLENDED = ("batido", "smoothie", "licuado", "licuada", "malteada", "jugo")
# Indicadores de que el huevo SÍ se cuece (≥71°C) → seguro. Sesgo a SEGURIDAD: un falso
# "crudo" solo añade una nota inocua; un falso "cocido" sería peligroso (omitiría la nota),
# así que se exigen términos ESPECÍFICOS de huevo cocido, NO genéricos ambiguos. Nota:
# "tortilla" a secas es el pan plano (wrap) en es-DO, NO la tortilla de huevo → se exige
# "tortilla de huevo" explícito para no dar por cocido un huevo crudo dentro de un wrap.
_EGG_COOK_INDICATORS = (
    "tortilla de huevo", "tortilla espanola", "revoltillo", "revuelto", "omelet", "omelette",
    "huevo frito", "huevos fritos", "huevo cocid", "huevos cocid", "huevo hervi", "huevos hervi",
    "huevo duro", "huevos duros", "escalfad", "poche", "huevo estrellad", "huevos estrellad",
    "pasado por agua", "cocina el huevo", "cocina los huevo", "cuece el huevo", "cuece los huevo",
    "frie el huevo", "frie los huevo", "fríe el huevo", "fríe los huevo",
)


def _meal_has_egg(meal: dict, strip_accents) -> bool:
    """True si algún ingrediente del meal contiene huevo/clara/yema (token aislado)."""
    import re as _re
    for ing in meal.get("ingredients", []) or []:
        ing_low = strip_accents(str(ing).lower())
        for t in _RAW_EGG_TERMS:
            if _re.search(r"\b" + t + r"\b", ing_low):
                return True
    return False


def _meal_egg_is_cooked(meal: dict, strip_accents) -> bool:
    """True si el nombre o la receta del meal indica que el huevo se cocina (≥71°C)."""
    parts = [str(meal.get("name", ""))]
    rec = meal.get("recipe")
    if isinstance(rec, list):
        parts.extend(str(s) for s in rec)
    text = strip_accents(" ".join(parts).lower())
    return any(c in text for c in _EGG_COOK_INDICATORS)


def _scan_raw_egg_violations(plan: dict) -> list:
    """[P3-FOOD-SAFETY · 2026-06-13] Detector determinista de huevo crudo/poco cocido.
    Retorna lista de (day_idx, meal_idx, meal_name, kind) con kind ∈ {'blended','no_cook'}:
    - 'blended': huevo en una preparación licuada (batido/jugo) → CRUDO inequívoco.
    - 'no_cook': huevo presente y ningún indicador de cocción en nombre/receta → riesgo.
    Sesgo a sobre-detectar (seguridad > comodidad); el auto-fix es macro-preservante y no
    rompe la coherencia receta↔lista (no muta el token canónico del ingrediente)."""
    try:
        from constants import strip_accents
    except Exception:
        def strip_accents(s):
            import unicodedata
            return "".join(c for c in unicodedata.normalize("NFKD", str(s)) if not unicodedata.combining(c))
    violations = []
    for di, day in enumerate(plan.get("days", []) or []):
        for mi, meal in enumerate(day.get("meals", []) or []):
            if not _meal_has_egg(meal, strip_accents):
                continue
            name_low = strip_accents(str(meal.get("name", "")).lower())
            if any(b in name_low for b in _NO_COOK_BLENDED):
                violations.append((di, mi, meal.get("name", "?"), "blended"))
            elif not _meal_egg_is_cooked(meal, strip_accents):
                violations.append((di, mi, meal.get("name", "?"), "no_cook"))
    return violations


# Notas de seguridad (prominentes, accionables) que el auto-fix inyecta a la receta.
# [P3-PROTEIN-POWDER-REMOVE · 2026-06-22] Esta nota ya NO sugiere proteína en polvo (suplemento
