def _add_missing_recipe_step_carbs(days, db=None, allergies=None) -> int:
    """[P2-STEP-CARB-GHOST · 2026-07-01] (batch P1-DISH-REALISM-BATCH) Espejo del veg-guard para CARBS
    fantasma: "Revoltillo Criollo con Queso y AVENA" cuyos pasos dicen "cocinar la avena" y "servir junto
    a la avena cremosa" pero avena NO está en ingredients[] → ni se cuenta ni se compra (receta rota). El
    veg-guard solo materializa vegetales (≤60 kcal) y el name-fix solo proteínas fantasma — los carbs se
    escapaban. Materializa una porción MODESTA del carb (curado, slot-neutro) cuando el token aparece en
    el NOMBRE o en ≥1 paso de cocción y no hay exclude ("harina de avena"). Truth-up en el caller (patrón
    veg-guard). Filtro de alérgenos vía SSOT scan sobre la línea candidata (avena/gluten). Idempotente.
    tooltip-anchor: P2-STEP-CARB-GHOST"""
    if not RECIPE_STEP_CARB_GUARD_ENABLED or not days:
        return 0
    try:
        from constants import strip_accents as _sa
        added = 0
        for _d in days:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                ings = meal.get("ingredients")
                if not isinstance(ings, list):
                    continue
                rec = meal.get("recipe") if isinstance(meal.get("recipe"), list) else []
                hay = _sa((str(meal.get("name") or "") + " "
                           + " ".join(str(s) for s in rec if not _is_recipe_safety_note_step(s))).lower())
                ing_hay = _sa(" ".join(str(i) for i in ings).lower())
                # [P1-STEP-NUT-GHOST · 2026-07-05] frutos secos fantasma comparten el mecanismo
                # completo del carb-ghost (detección nombre+pasos, excludes, scan de alérgenos).
                # [P2-STEP-FRUIT-GHOST · 2026-07-05] + frutas frescas (uvas del plan 55846e5e).
                _ghosts = (_STEP_CARB_GHOSTS
                           + (_STEP_NUT_GHOSTS if RECIPE_STEP_NUT_GUARD_ENABLED else ())
                           + (_STEP_FRUIT_GHOSTS if RECIPE_STEP_FRUIT_GUARD_ENABLED else ()))
                for token, line, excludes in _ghosts:
                    if not _re.search(r"\b" + token, hay):
                        continue
                    if _re.search(r"\b" + token, ing_hay):
                        continue  # ya está en ingredientes
                    if any(ex in hay or ex in ing_hay for ex in excludes):
                        continue
                    if allergies:
                        try:
                            if _scan_allergen_violations({"days": [{"meals": [{"ingredients": [line]}]}]},
                                                         allergies):
                                continue  # el carb candidato viola una alergia declarada (avena→gluten)
                        except Exception:
                            continue  # scan falló → conservador: no materializar
                    ings.append(line)
                    if isinstance(meal.get("ingredients_raw"), list):
                        meal["ingredients_raw"].append(line)
                    added += 1
        return added
    except Exception as _cg_e:
        logger.warning(f"[P2-STEP-CARB-GHOST] guard no-op: {type(_cg_e).__name__}: {_cg_e}")
        return 0


# [P1-BUDGET-TIER-LEVERS · 2026-07-02] Backstop determinista del tier "Económico".
# El prompt ya guía al LLM hacia ingredientes económicos (build_budget_context), pero
# es advisory: cuando se cuela un premium (salmón/almendras/quinoa) en un plan cuyo
# formulario pidió "Económico — lo básico y esencial" (o `custom` con monto ajustado,
# ver nutrition_calculator.budget_prefers_economy), este pase lo sustituye por un
# equivalente CULINARIO de la misma categoría, macro-similar y verificado del catálogo.
# Corre PRE-engine (mismo racional que veg-guard/carb-ghost: la sustitución entra al
# allergen scan, sizing, quantize, closers, compras y coherence — coherente E2E).
# NUNCA toca pisos clínicos ni alergias (candidato pasa _scan_allergen_violations y
# dislikes; sin resolución de precio en catálogo → skip). Acotado (max subs por plan)
# + marcado honesto: meal._budget_substitutions + plan._budget_adjusted (la
# reconciliación P1-BUDGET-RECONCILE lo expone al usuario).
# Rollback sin redeploy: MEALFIT_BUDGET_CHEAPEN_PASS=false.
# Tooltip-anchor: P1-BUDGET-TIER-LEVERS. Test: test_p1_budget_intelligence.py.
BUDGET_CHEAPEN_PASS_ENABLED = _env_bool("MEALFIT_BUDGET_CHEAPEN_PASS", True)
BUDGET_CHEAPEN_MAX_SUBS = _env_int("MEALFIT_BUDGET_CHEAPEN_MAX_SUBS", 3, lambda v: 0 <= v <= 10)
# [P1-BUDGET-CONVERGENCE · 2026-07-03] (audit v6 · P1-3) Pasada de convergencia POST-costeo:
# conocido el costo real, si la reconciliación dio `excedido` (CUALQUIER tier con referencia,
# no solo economía) → una pasada extra del cheapen (force) → re-banda → rebuild de listas →
# re-costeo → re-reconciliación. Acotado a 1 pasada. Ver bloque en assemble_plan_node.
BUDGET_CONVERGENCE_ENABLED = _env_bool("MEALFIT_BUDGET_CONVERGENCE", True)
# [P1-BUDGET-DRIVER-AWARE · 2026-07-04] (audit v7 · P1-2) El cerebro de la convergencia deja
# de ser ciego: en vez de barrer días en orden contra la tabla estática de 8 pares, RANKEA los
# ítems que realmente encarecen la lista costeada (`estimated_cost_rd` desc) y ataca esos
# drivers con familias culinarias curadas (pescado→pescado, queso→queso, fruta→fruta...) cuyo
# candidato se valida contra el precio VIVO del catálogo master (≥30% más barato). Cierra el
# gap del audit v7: "un plan `excedido` cuyos ítems caros no están entre los 8 pares recibe
# 0 sustituciones y permanece excedido tras la convergencia". La tabla estática queda como
# BACKSTOP (corre después, idempotente — los tokens ya sustituidos no re-matchean).
# Rollback sin redeploy: MEALFIT_BUDGET_DRIVER_AWARE=false.
# Tooltip-anchor: P1-BUDGET-DRIVER-AWARE. Test: test_p1_budget_driver_aware.py.
BUDGET_DRIVER_AWARE_ENABLED = _env_bool("MEALFIT_BUDGET_DRIVER_AWARE", True)
BUDGET_DRIVER_AWARE_MAX_SUBS = _env_int("MEALFIT_BUDGET_DRIVER_AWARE_MAX_SUBS", 5, lambda v: 0 <= v <= 12)
BUDGET_DRIVER_AWARE_TOP_ITEMS = _env_int("MEALFIT_BUDGET_DRIVER_AWARE_TOP_ITEMS", 8, lambda v: 1 <= v <= 25)
# Ahorro mínimo por libra para que la sustitución valga (candidato < original × (1 - pct)).
# Mismo umbral 30% de la tabla estática (`cand_price >= orig_price * 0.7 → skip`).
BUDGET_DRIVER_AWARE_MIN_SAVING_PCT = _env_float(
    "MEALFIT_BUDGET_DRIVER_AWARE_MIN_SAVING_PCT", 0.30, lambda v: 0.0 <= v <= 0.9
)

# (regex del alimento premium, candidato económico del catálogo, excludes accent-stripped).
# Misma categoría culinaria SIEMPRE (pescado→pescado, semilla→semilla, grano→grano) —
# sustituir cross-categoría cambia el plato y eso es decisión del LLM/usuario, no nuestra.
_BUDGET_CHEAP_EQUIVALENTS = (
    (r"salm[oó]n", "Filete de pescado blanco", ()),
    (r"camar[oó]n(?:es)?", "Filete de pescado blanco", ()),
    (r"bacalao", "Filete de pescado blanco", ()),
    (r"almendras?", "Maní", ("leche de almendra", "harina de almendra")),
    (r"nueces|nuez", "Maní", ("nuez moscada",)),
    (r"ch[ií]a", "Linaza", ()),
    (r"quinoa|quinua", "Arroz integral", ()),
    (r"yogurt griego|yogur griego", "Yogurt natural", ()),
    # [P2-HABAS-CHEAPEN · 2026-07-06] (review #14, plan 17c3fa8f) Habas RD$205/lb = 3-4× más
    # caras que otras legumbres (habichuelas rojas ~RD$53/lb, frijoles ~RD$72/lb) — driver #1
    # del exceso de presupuesto (RD$820, 4 paquetes). Misma familia (legumbre→legumbre guisada):
    # "habas guisadas" → "habichuelas rojas guisadas" es coherente es-DO. `\b` evita matchear
    # "habichuelas". Solo dispara sobre planes EXCEDIDOS (el cheapen no toca planes en presupuesto).
    (r"\bhabas?\b", "Habichuelas rojas", ("habichuela",)),
)


def _budget_master_price_per_lb(name: str, master_map: dict) -> float:
    """Precio/lb-equivalente de un alimento vía el catálogo master (exacto →
    contención word-boundary). 0.0 si no resuelve (fail-open)."""
    try:
        from constants import strip_accents as _sa
        key = _sa(str(name or "").strip().lower())
        if not key:
            return 0.0
        entry = master_map.get(key)
        if entry is None:
            padded = f" {key} "
            best = None
            for mk in master_map:
                if len(mk) >= 4 and f" {mk} " in padded:
                    if best is None or len(mk) > len(best):
                        best = mk
            entry = master_map.get(best) if best else None
        return float(entry) if entry else 0.0
    except Exception:
        return 0.0


def _budget_build_master_price_map() -> dict:
    """{nombre/alias accent-stripped → precio/lb-equivalente} del catálogo master.
    Per-unit → per-lb vía density/container. Fail-open: {}."""
    try:
        from shopping_calculator import get_master_ingredients
        from constants import strip_accents as _sa
        out: dict = {}
        for row in get_master_ingredients() or []:
            try:
                price = float(row.get("price_per_lb") or 0)
            except (TypeError, ValueError):
                price = 0.0
            if price <= 0:
                try:
                    ppu = float(row.get("price_per_unit") or 0)
                    basis = float(row.get("density_g_per_unit") or 0) or float(row.get("container_weight_g") or 0)
                    if ppu > 0 and basis > 0:
                        price = ppu * 453.592 / basis
                except (TypeError, ValueError):
                    price = 0.0
            if price <= 0:
                continue
            names = [row.get("name") or ""]
            aliases = row.get("aliases")
            if isinstance(aliases, list):
                names.extend(str(a) for a in aliases)
            for n in names:
                k = _sa(str(n).strip().lower())
                if k:
                    out.setdefault(k, price)
        return out
    except Exception:
        return {}


def _apply_budget_cheapen_pass(days, form_data, force: bool = False) -> int:
    """Sustituye hasta BUDGET_CHEAPEN_MAX_SUBS ingredientes premium por su
    equivalente económico cuando el presupuesto pide economía. Retorna nº de
    sustituciones. Fail-open total (0 y plan intacto ante cualquier duda).
    [P1-BUDGET-CONVERGENCE · 2026-07-03] `force=True` (pasada post-costeo) salta el
    gate de economía: el caller YA sabe que el plan excede su referencia (cualquier
    tier) — los guards de alergia/dislike/≥30%-más-barato/max-subs siguen intactos."""
    if not BUDGET_CHEAPEN_PASS_ENABLED or BUDGET_CHEAPEN_MAX_SUBS <= 0 or not days:
        return 0
    if not force:
        try:
            from nutrition_calculator import budget_prefers_economy
            if not budget_prefers_economy(form_data or {}):
                return 0
        except Exception:
            return 0
    try:
        from constants import strip_accents as _sa
        master_map = _budget_build_master_price_map()
        allergies = (form_data or {}).get("allergies")
        dislikes = {_sa(str(d).strip().lower()) for d in ((form_data or {}).get("dislikes") or []) if str(d).strip()}
        subs = 0
        for _d in days:
            if subs >= BUDGET_CHEAPEN_MAX_SUBS:
                break
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if subs >= BUDGET_CHEAPEN_MAX_SUBS:
                    break
                if not isinstance(meal, dict):
                    continue
                ings = meal.get("ingredients")
                if not isinstance(ings, list):
                    continue
                for idx, ing in enumerate(ings):
                    if subs >= BUDGET_CHEAPEN_MAX_SUBS:
                        break
                    if not isinstance(ing, str):
                        continue
                    low = _sa(ing.lower())
                    for rx, candidate, excludes in _BUDGET_CHEAP_EQUIVALENTS:
                        if any(ex in low for ex in excludes):
                            continue
                        m = _re.search(rf"\b(?:{rx})\b", ing, _re.IGNORECASE)
                        if not m:
                            continue
                        cand_low = _sa(candidate.lower())
                        # El candidato debe: existir con precio en catálogo, ser realmente
                        # más barato que el original (si el original resuelve), no estar
                        # en dislikes y no violar alergias declaradas.
                        cand_price = _budget_master_price_per_lb(candidate, master_map)
                        if cand_price <= 0:
                            continue
                        orig_price = _budget_master_price_per_lb(m.group(0), master_map)
                        if orig_price > 0 and cand_price >= orig_price * 0.7:
                            continue
                        if any(dk and dk in cand_low for dk in dislikes):
                            continue
                        if allergies:
                            try:
                                if _scan_allergen_violations(
                                    {"days": [{"meals": [{"ingredients": [candidate]}]}]}, allergies
                                ):
                                    continue
                            except Exception:
                                continue  # scan falló → conservador: no sustituir
                        new_line = _re.sub(rf"\b(?:{rx})\b", candidate, ing, count=1, flags=_re.IGNORECASE)
                        if new_line == ing:
                            continue
                        ings[idx] = new_line
                        raw = meal.get("ingredients_raw")
                        if isinstance(raw, list) and idx < len(raw) and isinstance(raw[idx], str):
                            raw[idx] = _re.sub(rf"\b(?:{rx})\b", candidate, raw[idx], count=1, flags=_re.IGNORECASE)
                        # Nombre honesto del plato: si menciona el premium, renombrar
                        # (el phantom-protein namefix corre después como backstop).
                        name = meal.get("name")
                        if isinstance(name, str) and _re.search(rf"\b(?:{rx})\b", name, _re.IGNORECASE):
                            meal["name"] = _re.sub(rf"\b(?:{rx})\b", candidate, name, count=1, flags=_re.IGNORECASE)
                        note = f"{m.group(0)} → {candidate}"
                        meal.setdefault("_budget_substitutions", []).append(note)
                        # [P2-AUDIT-V5-BATCH · 2026-07-02] (GAP-08) Reescribir también los PASOS de la
                        # receta: sin esto, "sella el salmón" sobrevivía con ingredients ya en pescado
                        # blanco (el pase tocaba ings/raw/name pero jamás meal['recipe']). Mismo helper
                        # conservador y mismo knob del path clínico (accent-loose, skip-tokens,
                        # idempotente, solo toca meal['recipe']). m.group(0) = forma exacta matcheada.
                        if SUBST_RECIPE_REWRITE_ENABLED:
                            try:
                                _rewrite_recipe_steps_after_subs(meal, [([m.group(0)], candidate)])
                            except Exception:
                                pass
                        logger.info(f"💰 [P1-BUDGET-TIER-LEVERS] Sustitución económica: {note} "
                                    f"(RD${orig_price:.0f}/lb → RD${cand_price:.0f}/lb)")
                        subs += 1
                        break
        return subs
    except Exception as _bcp_e:
        logger.warning(f"[P1-BUDGET-TIER-LEVERS] cheapen-pass no-op: {type(_bcp_e).__name__}: {_bcp_e}")
        return 0


# [P1-BUDGET-DRIVER-AWARE · 2026-07-04] Familias culinarias para la sustitución driver-aware.
# Cada regla: (regex del driver caro, tuple de candidatos económicos EN ORDEN DE PREFERENCIA
# culinaria, excludes accent-stripped). Doctrina intacta de P1-BUDGET-TIER-LEVERS: misma
# categoría culinaria SIEMPRE (cross-categoría cambia el plato — decisión del LLM/usuario).
# El orden de candidatos codifica juicio culinario (pescado blanco antes que sardina); el
# primer candidato que RESUELVE con precio en el catálogo master + pasa guards + ahorra
# ≥MIN_SAVING_PCT gana. Candidatos que no existen en el catálogo → skip silencioso
# (fail-open), así la tabla tolera drift del catálogo sin romper nada. Clínico: candidatos
# elegidos neutrales (sin altos-K tipo guineo — perfil renal), y el allergen-scan + dislikes
# del pase se aplican igual que en la tabla estática.
_BUDGET_DRIVER_FAMILIES = (
    # [P1-BUDGET-PREMIUM-SHELLFISH · 2026-07-07] (review plan vivo 4e7b8dbb: "Cangrejo" era el driver de
    # costo #1 — RD$599, RD$479/lb — pero NO estaba en la familia de mariscos → la convergencia lo rankeaba
    # #1 y no lo podía sustituir. Sustituto "Filete de pescado blanco" = RD$127.5/lb = ~73% más barato).
    # Añadidos cangrejo/jaiba/langostino/vieira/almeja/mejillón/lambí/ostra/concha a los premium ya cubiertos.
    (r"salm[oó]n|camar[oó]n(?:es)?|cangrejo|jaiba|langostino(?:s)?|langosta|vieira(?:s)?|almeja(?:s)?|"
     r"mejill[oó]n(?:es)?|lamb[ií]|ostra(?:s)?|concha(?:s)?|bacalao|mero|chillo|pulpo|at[uú]n\s+fresco",
     ("Filete de pescado blanco",), ()),
    (r"filete\s+de\s+res|lomo\s+de\s+res|churrasco|solomillo",
     ("Carne de res molida",), ()),
    (r"queso\s+(?:cheddar|gouda|parmesano|mozzarella|manchego|suizo|azul|brie)",
     ("Queso blanco", "Queso de freír"), ()),
    (r"almendras?|nueces|nuez|pistachos?|avellanas?|semillas?\s+de\s+cajuil|maca(?:damia)?s?",
     ("Maní",), ("leche de almendra", "harina de almendra", "nuez moscada")),
    (r"ch[ií]a", ("Linaza",), ()),
    (r"quinoa|quinua", ("Arroz integral",), ()),
    (r"yogurt\s+griego|yogur\s+griego", ("Yogurt natural",), ()),
    (r"fresas?|ar[aá]ndanos?|frambuesas?|moras?\b",
     ("Lechosa", "Piña"), ()),
)


def _apply_budget_driver_aware_pass(days, form_data, weekly_list) -> int:
    """[P1-BUDGET-DRIVER-AWARE · 2026-07-04] (audit v7 · P1-2) Sustitución económica
    guiada por el COSTO REAL: rankea los ítems más caros de la lista semanal costeada
    (`estimated_cost_rd` desc, top BUDGET_DRIVER_AWARE_TOP_ITEMS), resuelve la familia
    culinaria de cada driver y sustituye sus apariciones en el plan por el candidato
    económico preferido que valide contra el precio vivo del catálogo master. Retorna
    nº de líneas sustituidas (cap BUDGET_DRIVER_AWARE_MAX_SUBS). Guards idénticos a
    `_apply_budget_cheapen_pass`: alergias (`_scan_allergen_violations`), dislikes,
    ahorro mínimo, marcado honesto (`_budget_substitutions`), rewrite de nombre y de
    pasos de receta. Fail-open TOTAL (0 y plan intacto ante cualquier duda).
    tooltip-anchor: P1-BUDGET-DRIVER-AWARE"""
    if not BUDGET_DRIVER_AWARE_ENABLED or BUDGET_DRIVER_AWARE_MAX_SUBS <= 0:
        return 0
    if not days or not weekly_list:
        return 0
    try:
        from constants import strip_accents as _sa
        master_map = _budget_build_master_price_map()
        if not master_map:
            return 0
        allergies = (form_data or {}).get("allergies")
        dislikes = {_sa(str(d).strip().lower()) for d in ((form_data or {}).get("dislikes") or []) if str(d).strip()}

        # 1. Drivers: ítems con precio, de mayor a menor costo.
        priced = [
            it for it in weekly_list
            if isinstance(it, dict) and str(it.get("name") or "").strip()
        ]
        priced.sort(key=lambda x: float(x.get("estimated_cost_rd") or 0) or 0.0, reverse=True)
        drivers = [
            str(it.get("name")).strip()
            for it in priced[: max(1, BUDGET_DRIVER_AWARE_TOP_ITEMS)]
            if float(it.get("estimated_cost_rd") or 0) > 0
        ]
        if not drivers:
            return 0

        # 2. Resolver (regex, candidato validado) por driver, en orden de costo.
        resolved: list = []  # (rx, candidate)
        seen_rx: set = set()
        for drv in drivers:
            for rx, candidates, excludes in _BUDGET_DRIVER_FAMILIES:
                if rx in seen_rx:
                    continue
                if not _re.search(rf"\b(?:{rx})\b", drv, _re.IGNORECASE):
                    continue
                drv_low = _sa(drv.lower())
                if any(ex in drv_low for ex in excludes):
                    continue
                orig_price = _budget_master_price_per_lb(drv, master_map)
                for candidate in candidates:
                    cand_price = _budget_master_price_per_lb(candidate, master_map)
                    if cand_price <= 0:
                        continue  # candidato sin precio en catálogo → siguiente preferencia
                    if orig_price > 0 and cand_price >= orig_price * (1.0 - BUDGET_DRIVER_AWARE_MIN_SAVING_PCT):
                        continue  # no ahorra lo suficiente
                    cand_low = _sa(candidate.lower())
                    if any(dk and dk in cand_low for dk in dislikes):
                        continue
                    if allergies:
                        try:
                            if _scan_allergen_violations(
                                {"days": [{"meals": [{"ingredients": [candidate]}]}]}, allergies
                            ):
                                continue
                        except Exception:
                            continue  # scan falló → conservador: no sustituir
                    resolved.append((rx, candidate, excludes, orig_price, cand_price))
                    seen_rx.add(rx)
                    break
                break  # primera familia que matchea el driver decide
        if not resolved:
            return 0

        # 3. Sustituir apariciones en el plan (misma maquinaria del pase estático).
        subs = 0
        for _d in days:
            if subs >= BUDGET_DRIVER_AWARE_MAX_SUBS:
                break
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if subs >= BUDGET_DRIVER_AWARE_MAX_SUBS:
                    break
                if not isinstance(meal, dict):
                    continue
                ings = meal.get("ingredients")
                if not isinstance(ings, list):
                    continue
                for idx, ing in enumerate(ings):
                    if subs >= BUDGET_DRIVER_AWARE_MAX_SUBS:
                        break
                    if not isinstance(ing, str):
                        continue
                    low = _sa(ing.lower())
                    for rx, candidate, excludes, orig_price, cand_price in resolved:
                        if any(ex in low for ex in excludes):
                            continue
                        m = _re.search(rf"\b(?:{rx})\b", ing, _re.IGNORECASE)
                        if not m:
                            continue
                        new_line = _re.sub(rf"\b(?:{rx})\b", candidate, ing, count=1, flags=_re.IGNORECASE)
                        if new_line == ing:
                            continue
                        # [P2-SUBST-UNIT-DEDUP · 2026-07-05] "½ filete de mero" → candidato con la
                        # misma unidad líder → "filete de Filete de..." — colapsar en línea/raw/
                        # nombre/pasos (caso vivo del plan 23c958bb).
                        ings[idx] = _dedup_unit_noun_collision(new_line)
                        raw = meal.get("ingredients_raw")
                        if isinstance(raw, list) and idx < len(raw) and isinstance(raw[idx], str):
                            raw[idx] = _dedup_unit_noun_collision(
                                _re.sub(rf"\b(?:{rx})\b", candidate, raw[idx], count=1, flags=_re.IGNORECASE))
                        name = meal.get("name")
                        if isinstance(name, str) and _re.search(rf"\b(?:{rx})\b", name, _re.IGNORECASE):
                            meal["name"] = _dedup_unit_noun_collision(
                                _re.sub(rf"\b(?:{rx})\b", candidate, name, count=1, flags=_re.IGNORECASE))
                        note = f"{m.group(0)} → {candidate}"
                        meal.setdefault("_budget_substitutions", []).append(note)
                        if SUBST_RECIPE_REWRITE_ENABLED:
                            try:
                                _rewrite_recipe_steps_after_subs(meal, [([m.group(0)], candidate)])
                                _rec_dd = meal.get("recipe")
                                if isinstance(_rec_dd, list):
                                    meal["recipe"] = [
                                        _dedup_unit_noun_collision(s2) if isinstance(s2, str) else s2
                                        for s2 in _rec_dd]
                            except Exception:
                                pass
                        logger.info(
                            f"💰 [P1-BUDGET-DRIVER-AWARE] Sustitución driver-aware: {note} "
                            f"(RD${orig_price:.0f}/lb → RD${cand_price:.0f}/lb)"
                        )
                        subs += 1
                        break
        return subs
    except Exception as _bda_e:
        logger.warning(f"[P1-BUDGET-DRIVER-AWARE] pase no-op: {type(_bda_e).__name__}: {_bda_e}")
        return 0


# [P2-SUBST-UNIT-DEDUP · 2026-07-05] (screenshot del plan vivo 23c958bb) "½ filete de mero" +
# candidato "Filete de pescado blanco" → "½ filete de Filete de pescado blanco": la sustitución
# textual no ve que la UNIDAD del lead ya es el sustantivo líder del candidato. Colapsa
# "<unidad> de <misma-unidad> de" → "<unidad> de" (case/acento-insensible), preservando plural.
_SUBST_UNIT_DEDUP_RE = _re.compile(
    r"\b(filete|pieza|lonja|rodaja|taza|lata)(s)?\s+de\s+\1\s+de\s+", _re.IGNORECASE)


def _dedup_unit_noun_collision(text: str) -> str:
    """[P2-SUBST-UNIT-DEDUP · 2026-07-05] SSOT del colapso post-sustitución. Puro, fail-safe."""
    try:
        return _SUBST_UNIT_DEDUP_RE.sub(lambda m: f"{m.group(1)}{m.group(2) or ''} de ", str(text))
    except Exception:
        return text


# [P1-CURED-GHOST-STEPS · 2026-07-05] frases de DESALADO (aplican a curados; absurdas sobre
# fresco: "Desala el filete de pescado blanco remojándolo 2 horas" — plan 55846e5e).
_DESALT_PHRASE_RE = _re.compile(
    r"[^.:]*\b(?:desala\w*|remoj[aá]\w*|cambiando\s+el\s+agua)\b[^.]*\.?\s*", _re.IGNORECASE)
_PILLAR_PREFIX_RE = _re.compile(r"^\s*(mise en place|el toque de fuego|montaje)\s*:?\s*", _re.IGNORECASE)


def _strip_desalt_instructions(meal: dict) -> int:
    """[P1-CURED-GHOST-STEPS · 2026-07-05] Elimina las FRASES de desalado/remojo de los pasos
    (preservando el prefijo del pilar). Se invoca cuando la proteína curada fue swapeada a
    fresca o cuando sus menciones fantasma se reescriben. Fail-safe → 0."""
    try:
        rec = meal.get("recipe")
        if not isinstance(rec, list):
            return 0
        fixed = 0
        out = []
        for s in rec:
            if not isinstance(s, str) or _is_recipe_safety_note_step(s) \
                    or not _re.search(r"desala|remoj", s, _re.IGNORECASE):
                out.append(s)
                continue
            _mpref = _PILLAR_PREFIX_RE.match(s)
            _pref = s[:_mpref.end()] if _mpref else ""
            _body = s[_mpref.end():] if _mpref else s
            _new_body = _DESALT_PHRASE_RE.sub("", _body).strip()
            if _new_body:
                out.append((_pref + _new_body) if _pref else _new_body)
                fixed += 1
            elif _pref:
                out.append(_pref.rstrip(": ") + ": continúa con la preparación.")
                fixed += 1
            else:
                fixed += 1  # paso íntegramente de desalado → se elimina
        if fixed:
            meal["recipe"] = out
        return fixed
    except Exception:
        return 0


_GHOST_CURED_TOKENS = ("arenque", "bacalao", "salami", "salchichon", "pepperoni",
                       "mortadela", "tocino", "panceta", "longaniza", "chorizo")
_GHOST_PRESENT_PROTEIN_TOKENS = ("sardina", "atun", "pescado", "pollo", "pavo", "res",
                                 "cerdo", "camaron", "huevo", "queso", "yogur")


def _rewrite_cured_ghost_protein_steps(days) -> int:
    """[P1-CURED-GHOST-STEPS · 2026-07-05] (plan 55846e5e: pasos guisando ARENQUE que NO está en
    la lista — la línea curada fue removida/swapeada por otro pase y sus pasos sobrevivieron:
    "Desala el arenque… Incorpora el arenque desmenuzado" cocinando un fantasma). Dirección
    INVERSA al ghost de frutas/frutos secos: materializar un curado-en-sal regalaría el sodio de
    vuelta → se REESCRIBEN las menciones hacia la proteína que SÍ está en el plato (nombre +
    pasos) y se eliminan las frases de desalado. Sin proteína presente → solo strip de desalado
    (conservador: jamás inventar). Idempotente. tooltip-anchor: P1-CURED-GHOST-STEPS"""
    try:
        from constants import strip_accents as _sa_cg
        fixed = 0
        for _d in days or []:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                ings = meal.get("ingredients")
                if not isinstance(ings, list):
                    continue
                rec = meal.get("recipe") if isinstance(meal.get("recipe"), list) else []
                blob = _sa_cg((str(meal.get("name") or "") + " "
                               + " ".join(str(s) for s in rec
                                          if not _is_recipe_safety_note_step(s))).lower())
                ing_blob = _sa_cg(" ".join(str(i) for i in ings).lower())
                for tok in _GHOST_CURED_TOKENS:
                    if not _re.search(r"\b" + tok, blob) or _re.search(r"\b" + tok, ing_blob):
                        continue
                    # proteína PRESENTE en la lista → destino del rewrite.
                    _repl_food = None
                    for pt in _GHOST_PRESENT_PROTEIN_TOKENS:
                        _line = next((str(i) for i in ings
                                      if isinstance(i, str) and pt in _sa_cg(i.lower())), None)
                        if _line:
                            _repl_food = _re.sub(
                                _LEAD_QTY_UNIT_STRIP_RE, "",
                                _re.sub(r"\([^)]*\)", "", _line)).strip(" ,.-")
                            break
                    if _repl_food:
                        try:
                            _rewrite_recipe_steps_after_subs(meal, [([tok], _repl_food)])
                        except Exception:
                            pass
                        _nm = str(meal.get("name") or "")
                        _pat_cg = _re.compile(r"\b" + _accent_flex_pattern(tok) + r"\w*", _re.IGNORECASE)
                        if _pat_cg.search(_nm):
                            meal["name"] = _pat_cg.sub(
                                _repl_food[:1].upper() + _repl_food[1:], _nm, count=1)
                    _strip_desalt_instructions(meal)
                    meal["_cured_ghost_rewritten"] = tok
                    fixed += 1
                    logger.info(f"🐟 [P1-CURED-GHOST-STEPS] '{tok}' fantasma en pasos (sin línea en "
                                f"la lista) → {'reescrito a ' + repr(_repl_food) if _repl_food else 'desalado eliminado'} "
                                f"| meal={str(meal.get('name'))[:40]}")
        return fixed
    except Exception as _cg_e:
        logger.warning(f"[P1-CURED-GHOST-STEPS] no-op: {type(_cg_e).__name__}: {_cg_e}")
        return 0


def _restore_display_from_raw_orphans(days) -> int:
    """[P1-DISPLAY-RESTORE-FROM-RAW · 2026-07-06] La mitad INVERSA de
    P2-RAW-DISPLAY-RECONCILE — cierra (mitigando) el P1 crónico de los
    display-droppers: pases históricos QUITAN/renombran líneas del display sin
    tocar raw (la mozzarella del wrap con Mise y Montaje que la usan; el 'Sal
    al gusto' del autofix de sodio) → el usuario no ve en Ingredientes algo que
    la receta usa y la lista compra. Reparación conservadora en la FRONTERA:
    fila de raw cuyo stem no aparece en NINGUNA línea del display Y SÍ se usa
    en los pasos no-nota → se re-AÑADE al display (prettificada). Cap 3/meal.
    El WARN [P1-RAW-MISALIGN] sigue emitiéndose para cazar al dropper de raíz.
    tooltip-anchor: P1-DISPLAY-RESTORE-FROM-RAW"""
    try:
        from constants import strip_accents as _sa_rd
        try:
            from humanize_ingredients import _prettify_quantity_display as _pretty_rd
        except Exception:
            def _pretty_rd(s):
                return s
        restored = 0
        for _d in days or []:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                ings = meal.get("ingredients")
                raw = meal.get("ingredients_raw")
                rec = meal.get("recipe")
                if not isinstance(ings, list) or not isinstance(raw, list) or not isinstance(rec, list):
                    continue
                if len(raw) <= len(ings):
                    continue  # solo la dirección raw>display (droppers)
                _disp_blob = _sa_rd(" ".join(str(x) for x in ings).lower())
                _steps_blob = _sa_rd(" ".join(
                    str(s) for s in rec
                    if isinstance(s, str) and not _is_recipe_safety_note_step(s)
                    and not str(s).strip().startswith(("💡", "💪", "🌱", "🧉", "🏷"))
                ).lower())
                _meal_restored = 0
                _phantoms = []
                for r in raw:
                    if _meal_restored >= 3:
                        break
                    if not isinstance(r, str) or not r.strip():
                        continue
                    _food = _re.sub(_LEAD_QTY_UNIT_STRIP_RE, "", _sa_rd(r.lower())).strip()
                    # Tokens del ALIMENTO (todos, no solo el primero: "queso mozzarella"
                    # con pasos que dicen solo "mozzarella"). 'gusto'/'aprox' fuera
                    # ("Sal al gusto" no debe matchear el "al gusto" de otra línea).
                    _toks = [t for t in _re.split(r"[^\wáéíóúñü]+", _food)
                             if len(t) >= 3 and t not in ("gusto", "aprox", "aproximadamente")]
                    if not _toks:
                        continue
                    _cands = set()
                    for _t0 in _toks:
                        _cands.add(_t0)
                        if len(_t0) > 4 and _t0.endswith("s"):
                            _cands.add(_t0[:-1])
                        if len(_t0) > 5 and _t0.endswith("es"):
                            _cands.add(_t0[:-2])
                    def _hit(blob):
                        return any(_re.search(r"\b" + _re.escape(c) + r"(?:es|e|s)?\b", blob)
                                   for c in _cands)
                    if _hit(_disp_blob):
                        continue  # el display ya cubre este alimento
                    if not _hit(_steps_blob):
                        # [P2-RAW-PHANTOM-DROP · 2026-07-06] raw-huérfano que NI el display
                        # NI los pasos usan: si trae cantidad CUANTIFICADA ("50g de
                        # camarones cocido" en unos bollitos de queso, plan fcc7a9f0) es
                        # un fantasma de COMPRA — la lista lo compraría para una receta
                        # que no lo usa. Se marca para remover del raw. Los "al gusto"
                        # sin cantidad (sal/pimienta) se quedan (despensa implícita).
                        if _re.match(r"^\s*\d", str(r)):
                            _phantoms.append(r)
                        continue
                    try:
                        _line = _pretty_rd(str(r))
                    except Exception:
                        _line = str(r)
                    ings.append(_line)
                    _disp_blob += " " + _sa_rd(str(_line).lower())
                    restored += 1
                    _meal_restored += 1
                # [P2-RAW-PHANTOM-DROP] remover los fantasmas cuantificados del raw.
                if _phantoms:
                    meal["ingredients_raw"] = [x for x in raw if x not in _phantoms]
                    logger.info(
                        f"🧾 [P2-RAW-PHANTOM-DROP] {len(_phantoms)} fila(s) raw cuantificadas sin "
                        f"uso en display NI pasos removidas (compra fantasma) | "
                        f"meal={str(meal.get('name'))[:40]} | {[str(p)[:38] for p in _phantoms]}")
        if restored:
            logger.info(f"🧾 [P1-DISPLAY-RESTORE-FROM-RAW] {restored} línea(s) usadas en pasos "
                        f"restauradas al display (los droppers de raíz siguen bajo WARN misalign).")
        return restored
    except Exception as _rd_e:
        logger.warning(f"[P1-DISPLAY-RESTORE-FROM-RAW] no-op: {type(_rd_e).__name__}: {_rd_e}")
        return 0


# [P1-FINALIZE-COUNTABLE-POLISH] Marca del súper en línea de receta: UN token capitalizado
# solo entre paréntesis ("(Campos)", "(Wala)"). Las anotaciones legítimas van en minúscula
# o con dígitos ("(105g)", "(jugo)", "(porción)", "(37 g crudo)") → no matchean.
_BRAND_PAREN_RE = _re.compile(r"\s*\(\s*[A-ZÁÉÍÓÚÑ][A-Za-záéíóúñü]{2,}\s*\)")
# Dup unidad-alimento: "1 filete de Filete de pescado blanco" (el pase de presupuesto insertó
# la forma canónica dentro de una línea que ya traía la unidad homónima).
_UNIT_FOOD_DUP_RE = _re.compile(r"\b(\w+)\s+de\s+\1\s+de\b", _re.IGNORECASE)
_CITRUS_LEAD_RE = _re.compile(r"^\s*(\d+(?:[.,]\d+)?)\s+(limón|limon|limones|lima|limas)\b",
                              _re.IGNORECASE)
# [P2-MANI-GENDER-STEP · 2026-07-06] "maní" (masc mass-noun) + adjetivo de cocción con género/
# número errado en la prosa de un paso → masc singular ("maní fileteadas" → "maní fileteado").
_MANI_GENDER_STEP_RX = _re.compile(
    r"\b(man[ií])\s+(filetead|tostad|picad|molid|pelad|salad|dorad|frit|asad)[oa]s?\b",
    _re.IGNORECASE)


# [P2-STEP-PHRASE-DEDUP · 2026-07-06] (review #14) frase de alimento duplicada adyacente en pasos:
# "mezcla con queso blanco y queso blanco batidos" (batata rellena, plan 17c3fa8f) — artefacto del
# LLM. Colapsa "X y X" (X = 1-3 palabras idénticas, backref exacto) → "X". No toca "X y Y" (Y≠X).
_REPEATED_PHRASE_RX = _re.compile(
    r"\b([a-záéíóúñü]+(?: [a-záéíóúñü]+){0,2}) y \1\b", _re.IGNORECASE)


def _dedup_repeated_phrase(text: str) -> str:
    prev = None
    out = str(text)
    # itera hasta punto fijo (por si hay "X y X y X")
    while out != prev:
        prev = out
        out = _REPEATED_PHRASE_RX.sub(r"\1", out)
    return _re.sub(r"\s{2,}", " ", out)


def _dedup_repeated_phrases_in_plan(days) -> int:
    """[P2-STEP-PHRASE-DEDUP · 2026-07-06] Colapsa "alimento y alimento" duplicado en pasos e
    ingredientes. Idempotente. Fail-safe. tooltip-anchor: P2-STEP-PHRASE-DEDUP"""
    try:
        n = 0
        for _d in days or []:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                for _key in ("recipe", "ingredients", "ingredients_raw"):
                    _lst = meal.get(_key)
                    if not isinstance(_lst, list):
                        continue
                    for i, s in enumerate(_lst):
                        if isinstance(s, str) and " y " in s:
                            _new = _dedup_repeated_phrase(s)
                            if _new != s:
                                _lst[i] = _new
                                n += 1
        if n:
            logger.info(f"🪶 [P2-STEP-PHRASE-DEDUP] {n} frase(s) 'X y X' duplicada(s) colapsada(s).")
        return n
    except Exception as _dp_e:
        logger.warning(f"[P2-STEP-PHRASE-DEDUP] no-op: {type(_dp_e).__name__}: {_dp_e}")
        return 0


def _polish_finalize_display(days) -> int:
    """[P1-FINALIZE-COUNTABLE-POLISH · 2026-07-06] Pulido de FRONTERA tras la última mutación
    de cantidades (review #13). Cuatro reglas:
    1. Decimales no-medibles en el DISPLAY → re-quantize display-only ("2.97 limones"→"3
       limones", "1.49 dientes"→"1½ dientes", "3.39 dientes"→"3½"): el re-trim de banda
       post-quantize re-escala líneas (3×0.99=2.97) y nadie re-redondea. El RAW no se toca
       (fuente de macros/lista) — drift visual acotado por guard de factor [0.6, 1.67].
    2. "1 filete de Filete de pescado blanco" → "1 filete de pescado blanco" (display+raw).
    3. Marca del súper fuera de la receta: "arroz blanco (Campos)" → "arroz blanco"
       (display+raw; la marca vive en lista/Nevera — acá la copió el LLM del contexto de
       personalización de marcas).
    4. Cap cítrico por comida (espejo receta del P6-CITRUS-CAP): lead > CITRUS_MEAL_CAP_UNITS
       limones/limas → clamp (display+raw; ≤12 kcal de drift, la lista deja de sobre-demandar
       contra el cap semanal). tooltip-anchor: P1-FINALIZE-COUNTABLE-POLISH"""
    if not FINALIZE_DISPLAY_POLISH:
        return 0
    try:
        from nutrition_db import quantize_ingredient_string as _qis
        try:
            from humanize_ingredients import _prettify_quantity_display as _pretty_pf
        except Exception:
            def _pretty_pf(s):
                return s
        changed = 0

        def _shared_clean(s: str) -> str:
            """Reglas 2+3+4 — aplican a display Y raw."""
            out = _BRAND_PAREN_RE.sub("", s)
            out = _UNIT_FOOD_DUP_RE.sub(r"\1 de", out)
            _mc = _CITRUS_LEAD_RE.match(out)
            if _mc:
                try:
                    _q = float(_mc.group(1).replace(",", "."))
                    if _q > CITRUS_MEAL_CAP_UNITS:
                        _cap_txt = (f"{CITRUS_MEAL_CAP_UNITS:g}")
                        out = out[:_mc.start(1)] + _cap_txt + out[_mc.end(1):]
                except (TypeError, ValueError):
                    pass
            return _re.sub(r"\s{2,}", " ", out).strip()

        def _messy_decimal(s: str) -> bool:
            # Cualquier lead decimal ("1.49", "2.97", "3.39") se re-quantiza: aunque el
            # VALOR esté cerca de la grilla (1.49≈1.5), el STRING no es forma de cocina.
            # quantize es no-op (factor 1.0) para valores ya en grilla.
            return bool(_re.match(r"\s*\d+\.\d+\b", str(s)))

        for _d in days or []:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                for _key in ("ingredients", "ingredients_raw"):
                    _lst = meal.get(_key)
                    if not isinstance(_lst, list):
                        continue
                    for i, s in enumerate(_lst):
                        if not isinstance(s, str) or not s.strip():
                            continue
                        new_s = _shared_clean(s)
                        # Regla 1 SOLO display: raw es fuente de macros/lista.
                        if _key == "ingredients" and _messy_decimal(new_s):
                            try:
                                _snapped, _fac = _qis(new_s)
                                if 0.6 <= _fac <= 1.67:
                                    new_s = _snapped
                            except Exception:
                                pass
                        if _key == "ingredients":
                            try:
                                new_s = _pretty_pf(new_s)
                            except Exception:
                                pass
                        if new_s != s:
                            _lst[i] = new_s
                            changed += 1
        if changed:
            logger.info(f"🪄 [P1-FINALIZE-COUNTABLE-POLISH] {changed} línea(s) pulidas en frontera "
                        f"(decimales/dup-unidad/marca/cap-cítrico).")
        return changed
    except Exception as _pf_e:
        logger.warning(f"[P1-FINALIZE-COUNTABLE-POLISH] no-op: {type(_pf_e).__name__}: {_pf_e}")
        return 0


# [P2-CLOSER-STEP-BOUNDARY-DEDUP] Solo las variantes NO-cocción del paso 💪 (mezclar/escurrir
# no aportan información si la receta ya trabaja el alimento). "Cocina X..." se conserva:
# puede ser la única instrucción de cocción aunque el Montaje mencione el alimento al servir.
_CLOSER_MIX_STEP_RE = _re.compile(
    r"^💪\s*(?:Escurre e incorpora|Incorpora)\s+(.+?)\s*(?:\(ya viene cocido\)\s*)?"
    r"a la preparación", _re.IGNORECASE)


def _dedup_redundant_closer_steps(days) -> int:
    """[P2-CLOSER-STEP-BOUNDARY-DEDUP · 2026-07-06] Espejo de FRONTERA del check
    P1-CLOSER-HYGIENE: si un paso 💪 tipo "Incorpora X a la preparación…" quedó
    REDUNDANTE porque otros pasos reales ya trabajan X (el Montaje de la piña dice
    "añade el queso cottage" y el 💪 "Incorpora queso" sobra — review #13, plan
    fcc7a9f0), se remueve. El check del injector corre en INSERT-time; pases
    posteriores pueden crear la redundancia después — este pase la caza al final,
    sea cual sea el ordering. tooltip-anchor: P2-CLOSER-STEP-BOUNDARY-DEDUP"""
    try:
        from constants import strip_accents as _sa_dd
        removed = 0
        for _d in days or []:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                rec = meal.get("recipe")
                if not isinstance(rec, list) or len(rec) < 2:
                    continue
                _others_blob = _sa_dd(" ".join(
                    str(s) for s in rec
                    if isinstance(s, str) and "💪" not in s
                    and not _is_recipe_safety_note_step(s)).lower())
                keep = []
                for s in rec:
                    _m = _CLOSER_MIX_STEP_RE.match(str(s).strip()) if isinstance(s, str) else None
                    if _m:
                        _toks = [t for t in _re.split(r"[^a-z]+", _sa_dd(_m.group(1).lower()))
                                 if len(t) >= 4 and t not in ("cocido", "cocida", "cocidos",
                                                              "cocidas", "agua", "aceite",
                                                              "lata", "latas")]
                        _stems = {t[:-1] if (t.endswith("s") and len(t) > 4) else t for t in _toks}
                        if _stems and any(
                                _re.search(r"\b" + _re.escape(st) + r"(?:s|es)?\b", _others_blob)
                                for st in _stems):
                            removed += 1
                            logger.info(f"🧹 [P2-CLOSER-STEP-BOUNDARY-DEDUP] paso 💪 redundante "
                                        f"removido (la receta ya trabaja el alimento) | "
                                        f"meal={str(meal.get('name'))[:40]} | {str(s)[:60]}")
                            continue
                    keep.append(s)
                if len(keep) != len(rec):
                    meal["recipe"] = keep
        return removed
    except Exception as _dd_e:
        logger.warning(f"[P2-CLOSER-STEP-BOUNDARY-DEDUP] no-op: {type(_dd_e).__name__}: {_dd_e}")
        return 0


def _reconcile_display_missing_in_raw(days) -> int:
    """[P2-RAW-DISPLAY-RECONCILE · 2026-07-05] (plan vivo 55846e5e: "8¾ cdta de miel" existía SOLO
    en `ingredients` — sin contraparte en `ingredients_raw`). La lista de compras Y los medidores
    (azúcares añadidos, micros, sodio) leen raw preferido → 62g de miel eran INVISIBLES (panel
    0/25 con la miel en el plato). Causa-clase: pases históricos mutaban display y raw de forma
    independiente (misalignment ya medido también en 3aa6e58a). Reconciliación CONSERVADORA:
    línea de display cuyo token principal (≥4 chars) no aparece en NINGUNA línea del raw → se
    APPENDEA al raw. Dirección segura: compras/medidores solo GANAN visibilidad; jamás se borra
    ni se modifica una línea existente del raw. Idempotente. Devuelve nº de líneas añadidas.
    tooltip-anchor: P2-RAW-DISPLAY-RECONCILE"""
    try:
        from constants import strip_accents as _sa_rr
        added = 0
        for _d in days or []:
            for meal in (_d.get("meals") or []) if isinstance(_d, dict) else []:
                if not isinstance(meal, dict):
                    continue
                ings = meal.get("ingredients")
                raw = meal.get("ingredients_raw")
                if not isinstance(ings, list) or not isinstance(raw, list):
                    continue
                _raw_blob = _sa_rr(" ".join(str(r) for r in raw).lower())
                for s in ings:
                    if not isinstance(s, str) or not s.strip():
                        continue
                    _food = _re.sub(_LEAD_QTY_UNIT_STRIP_RE,
                                    "", _sa_rr(s.lower())).strip()
                    _toks = [t for t in _re.split(r"[^\wáéíóúñü]+", _food) if len(t) >= 4]
                    if not _toks:
                        continue
                    # [P2-STEM-BOUNDED · 2026-07-06] token bounded (agua⊄aguacate): el substring
                    # abierto hacía que una línea de agua/atún-en-agua pareciera presente en un
                    # raw que solo tenía aguacate → la línea jamás ganaba visibilidad en compras.
                    # [P2-RECONCILE-PLURAL-STEM · 2026-07-06] el display humanizado viene en
                    # PLURAL ('4 tortillas integrales') y el raw crudo en singular ('4 tortilla
                    # integral') — 'tortillas(?:s|es)?' JAMÁS matchea 'tortilla' → append
                    # duplicado (pepino/tortillas/claras contados DOBLE en compras; verificado
                    # en el plan vivo cd4ae3c3, 9 meals raw>display). Candidatos singularizados
                    # + sufijo (es|e|s) cubren ambas direcciones (tomates↔tomate, limones↔limón).
                    _t0 = _toks[0]
                    _cands = {_t0}
                    if len(_t0) > 4 and _t0.endswith("s"):
                        _cands.add(_t0[:-1])
                    if len(_t0) > 5 and _t0.endswith("es"):
                        _cands.add(_t0[:-2])
                    if not any(_re.search(r"\b" + _re.escape(_c) + r"(?:es|e|s)?\b", _raw_blob)
                               for _c in _cands):
                        raw.append(s)
                        _raw_blob += " " + _sa_rr(s.lower())
                        added += 1
        if added:
            logger.info(f"🧾 [P2-RAW-DISPLAY-RECONCILE] {added} línea(s) de display sin contraparte "
                        f"en raw → añadidas (compras/medidores recuperan visibilidad).")
        return added
    except Exception as _rr_e:
        logger.warning(f"[P2-RAW-DISPLAY-RECONCILE] no-op: {type(_rr_e).__name__}: {_rr_e}")
        return 0


# [P1-RAW-DISPLAY-RECONCILE-RECIPROCAL · 2026-07-07] (forense plan vivo 766893f4: "Puré de Sardinas"
# tenía ingredients_raw=10 líneas con "0.5 diente de ajo picado" que el DISPLAY humanizado (9 líneas)
# DROPEÓ — el usuario no veía el ajo en la receta aunque la lista de compras SÍ lo tenía). Es la
