def _detect_restricted_tokens(form_data: dict) -> frozenset:
    """[P0-ORCH-1] Extrae los tokens de alérgeno declarados en el formulario.

    Lee allergies / medicalConditions / dislikes / restrictions / intolerances
    (listas o strings), normaliza (lowercase + sin acentos) y matchea contra
    `_FALLBACK_ALLERGEN_KEYWORDS`. Over-detección es la dirección SEGURA: un
    falso positivo solo evita una proteína de más (cae al template neutral).
    """
    if not isinstance(form_data, dict):
        return frozenset()
    parts = []
    for key in ("allergies", "medicalConditions", "dislikes",
                "restrictions", "intolerances", "foodRestrictions"):
        v = form_data.get(key)
        if isinstance(v, (list, tuple, set)):
            parts.extend(str(x) for x in v)
        elif v:
            parts.append(str(v))
    if not parts:
        return frozenset()
    text = " ".join(parts).lower().translate(_FALLBACK_ACCENT_MAP)
    found = set()
    for token, keywords in _FALLBACK_ALLERGEN_KEYWORDS.items():
        for kw in keywords:
            if kw in text:
                found.add(token)
                break
    return frozenset(found)


def _diet_restricted_tokens(form_data: dict) -> frozenset:
    """[P1-DIET-HARD-GUARD · 2026-06-15] (gap-audit P1-3) Tokens del vocabulario de fallback
    (`_FALLBACK_ALLERGEN_KEYWORDS`) que un `dietType` veg* prohíbe, para que el fallback matemático sea
    diet-aware. SIN esto, escalar una violación vegana a crítico→fallback servía pollo/huevo/pescado igual
    (el pool[0] de cada slot es animal); con esto, cada slot cae a la plantilla de leguminosa/neutral
    (vegana). Anchor: P1-DIET-HARD-GUARD."""
    if not isinstance(form_data, dict):
        return frozenset()
    canon = _canonicalize_diet_type(form_data.get("dietType"))  # SSOT compartido con el scan (P1 fix)
    if canon == "vegan":
        return frozenset({"chicken", "fish", "shellfish", "beef", "pork", "egg", "dairy"})
    if canon == "vegetarian":
        return frozenset({"chicken", "fish", "shellfish", "beef", "pork"})
    if canon == "pescatarian":
        return frozenset({"chicken", "beef", "pork"})
    return frozenset()


def _fallback_restricted_tokens(form_data: dict) -> frozenset:
    """[P0-ORCH-1 · +P1-DIET-HARD-GUARD] Tokens restringidos del fallback: alérgenos (gateado por
    `MEALFIT_FALLBACK_ALLERGEN_FILTER`) UNIÓN tokens de `dietType` (gateado por `MEALFIT_DIET_HARD_GUARD` —
    el fallback debe ser veg-safe independientemente del filtro de alérgenos). Ambos OFF + dieta balanceada
    → vacío → fallback histórico idéntico."""
    tokens: set = set()
    if FALLBACK_ALLERGEN_FILTER:
        tokens |= _detect_restricted_tokens(form_data)
    if DIET_HARD_GUARD:
        tokens |= _diet_restricted_tokens(form_data)
    return frozenset(tokens)


def _select_safe_fallback_meal(pool: list, restricted_tokens: frozenset, day_number: int = 1):
    """[P0-ORCH-1] Plantilla del pool cuyos tokens NO intersectan las restricciones.
    El último elemento de cada pool es neutral (tokens vacíos), así que SIEMPRE hay
    un retorno seguro.

    [P2-FALLBACK-DAY-ROTATION · 2026-07-01] (audit v2 creatividad GAP-1, batch P2-AUDIT-V2-BATCH)
    Antes devolvía SIEMPRE la primera plantilla segura (`pool[0]`) y `_build_fallback_day` no usaba
    el día → un plan fallback de 7 días era byte-idéntico ("Pollo y Arroz" × 7), exactamente el
    anti-patrón de monotonía que el owner quiere erradicar. Ahora ROTA entre las plantillas SEGURAS
    por número de día: `safe[(day_number-1) % len(safe)]`. Determinista (mismo día → misma plantilla,
    preserva idempotencia del fallback) y cubre también el pool bariátrico curado (mismo callsite).
    tooltip-anchor: P2-FALLBACK-DAY-ROTATION"""
    safe = [tmpl for tmpl in (pool or []) if not (tmpl[1] & restricted_tokens)]
    if safe:
        try:
            _idx = (int(day_number) - 1) % len(safe)
        except Exception:
            _idx = 0
        return safe[_idx]
    # Inalcanzable en la práctica (pool[-1] es neutral); defensa por si un
    # refactor futuro elimina la entrada neutral.
    return pool[-1] if pool else None


def _fallback_is_bariatric(form_data: dict) -> bool:
    """[P1-FALLBACK-BARIATRIC-CURATED · 2026-06-28] True si el form declara condición bariátrica. Reusa el MISMO SSOT que
    cap_bariatric_portions (_has_condition + BARIATRIC_CONDITION_TERMS) sobre los 5 campos canónicos. Fail-safe: cualquier
    excepción / knob off / form_data None → False (cae al fallback genérico). tooltip-anchor: P1-FALLBACK-BARIATRIC-CURATED"""
    if not FALLBACK_BARIATRIC_CURATED_ENABLED or not isinstance(form_data, dict):
        return False
    try:
        from micronutrients import _has_condition
        from constants import BARIATRIC_CONDITION_TERMS as _BT_FB
        _c = []
        for _k in ("medicalConditions", "medical_conditions", "conditions", "otherConditions", "other_conditions"):
            _v = form_data.get(_k)
            if isinstance(_v, (list, tuple)):
                _c.extend(str(x) for x in _v)
            elif _v:
                _c.append(str(_v))
        return _has_condition(_c, _BT_FB)
    except Exception as _fbe:
        logger.warning(f"[P1-FALLBACK-BARIATRIC-CURATED] detección falló (no bloquea): {type(_fbe).__name__}: {_fbe}")
        return False


